              {isSubmitting ? <RefreshCw className="w-5 h-5 animate-spin" /> : <>{authView === 'login' ? 'Login' : 'Create Account'} <LogIn className="w-4 h-4 ml-3" /></>}
            </button>
          </form>

          <button 
            onClick={() => setAuthView(authView === 'login' ? 'signup' : 'login')}
            className="mt-8 text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-indigo-400 transition-all text-center"
          >
            {authView === 'login' ? "নতুন অ্যাকাউন্ট তৈরি করতে চান? এখানে ক্লিক করুন" : "ইতিমধ্যে অ্যাকাউন্ট আছে? লগইন করুন"}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Auth;

