      const saved = localStorage.getItem(`lumina_projects_${user.email}`);
      setProjects(saved ? JSON.parse(saved) : []);
    }
  }, [user]);

  const saveProject = (project: Project) => {
    if (!user) return;
    const updated = [project, ...projects.filter(p => p.id !== project.id)];
    setProjects(updated);
    localStorage.setItem(`lumina_projects_${user.email}`, JSON.stringify(updated));
  };

  const handleElevate = () => {
    if (!user) return;
    const elevatedUser = { ...user, role: 'Studio Admin' };
    setUser(elevatedUser);
    localStorage.setItem('lumina_session', JSON.stringify(elevatedUser));

    const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const updatedUsers = users.map((u: any) => u.email === user.email ? { ...u, role: 'Studio Admin', isApproved: true } : u);
    localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));
  };

  if (!user) return <Auth onLogin={setUser} />;

  return (
    <HashRouter>
      <div className="flex h-screen bg-[#020617] text-slate-100 overflow-hidden font-sans">
        {/* Desktop Header Window Controls (Mock) */}
        <div className="fixed top-0 inset-x-0 h-8 bg-black/40 backdrop-blur-md flex items-center justify-between px-6 z-[60] border-b border-white/5 select-none pointer-events-none">
           <div className="flex items-center space-x-2">
              <div className="w-2.5 h-2.5 rounded-full bg-rose-500/50" />
              <div className="w-2.5 h-2.5 rounded-full bg-amber-500/50" />
              <div className="w-2.5 h-2.5 rounded-full bg-emerald-500/50" />
           </div>
           <p className="text-[9px] font-black uppercase tracking-[0.4em] text-slate-600">Lumina Desktop Studio x64</p>
           <div className="w-20" />
        </div>

        <Sidebar isOpen={isSidebarOpen} toggle={() => setIsSidebarOpen(!isSidebarOpen)} activeMode={activeMode} setActiveMode={setActiveMode} lang={user.language} isAdmin={user.role === 'Studio Admin'} />

        <div className="flex-1 flex flex-col min-w-0 h-full relative pt-8">
          <Header user={user} onLogout={() => setUser(null)} setLanguage={(l) => setUser({...user, language: l})} onElevate={handleElevate} />

          <main className="flex-1 overflow-auto p-4 md:p-10 bg-gradient-to-br from-[#020617] to-[#0f172a]">
            <Routes>
              <Route path="/" element={<Dashboard projects={projects} setActiveMode={setActiveMode} user={user} />} />
              <Route path="/video" element={<VideoEditor onSave={saveProject} />} />
              <Route path="/photo" element={<PhotoEditor onSave={saveProject} />} />
              <Route path="/paint" element={<PaintStudio onSave={saveProject} />} />
              <Route path="/ads" element={<AdBuilder onSave={saveProject} />} />
              <Route path="/audiobook" element={<AudiobookStudio onSave={saveProject} />} />
              <Route path="/education" element={<EducationStudio />} />
              <Route path="/templates" element={<TemplatesGallery />} />
              <Route path="/admin" element={user.role === 'Studio Admin' ? <AdminPanel /> : <Navigate to="/" />} />
              <Route path="/profile" element={<UserProfilePage user={user} setUser={setUser} onLogout={() => setUser(null)} />} />
              <Route path="/storage" element={<CloudStorage projects={projects} />} />
              <Route path="/shop" element={<Shop user={user} />} />
              <Route path="/communication" element={<CommunicationStudio user={user} />} />
              <Route path="/office" element={<OfficeSuite user={user} onSave={saveProject} />} />
              <Route path="/support" element={<SupportCenter user={user} />} />
            </Routes>
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

