      const { password, ...userProfile } = admin;
      localStorage.setItem('lumina_session', JSON.stringify(userProfile));
      onLogin(userProfile);
    }
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    setIsSubmitting(true);

    const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');

    setTimeout(() => {
      setIsSubmitting(false);

      if (authView === 'login') {
        const user = users.find((u: any) => u.email.toLowerCase() === formData.email.toLowerCase() && u.password === formData.password);

        if (!user) {
          setError("ইমেল বা পাসওয়ার্ড ভুল। আবার চেষ্টা করুন।");
          return;
        }

        const { password, ...userProfile } = user;
        localStorage.setItem('lumina_session', JSON.stringify(userProfile));
        onLogin(userProfile);

      } else if (authView === 'signup') {
        if (!formData.name || !formData.email || !formData.password) {
