          <form onSubmit={handleAuth} className="space-y-8">
            {error && <div className="p-5 bg-rose-500/10 border border-rose-500/20 rounded-[1.5rem] text-rose-500 text-xs font-black uppercase flex items-center"><AlertCircle className="w-5 h-5 mr-4" />{error}</div>}
            {success && <div className="p-5 bg-emerald-500/10 border border-emerald-500/20 rounded-[1.5rem] text-emerald-500 text-xs font-black uppercase flex items-center"><CheckCircle2 className="w-5 h-5 mr-4" />{success}</div>}

            {authView === 'signup' && (
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Identity Name</label>
                <div className="relative group">
                  <User className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-600 transition-colors group-focus-within:text-indigo-500" />
                  <input required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full bg-slate-950/50 border border-slate-800 rounded-3xl py-5 pl-16 pr-6 text-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all" placeholder="John Doe" />
                </div>
              </div>
            )}

            <div className="space-y-3">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Node Email</label>
              <div className="relative group">
                <Mail className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-600 transition-colors group-focus-within:text-indigo-500" />
                <input required type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full bg-slate-950/50 border border-slate-800 rounded-3xl py-5 pl-16 pr-6 text-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all" placeholder="node@lumina.studio" />
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Secret Key</label>
              <div className="relative group">
                <Lock className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-600 transition-colors group-focus-within:text-indigo-500" />
                <input required type={showPassword ? "text" : "password"} value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full bg-slate-950/50 border border-slate-800 rounded-3xl py-5 pl-16 pr-16 text-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all" placeholder="••••••••" />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-600 hover:text-white transition-colors">
                  {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                </button>
              </div>
            </div>

            <button disabled={isSubmitting} className="w-full py-6 bg-indigo-600 hover:bg-indigo-500 text-white rounded-[2rem] font-black uppercase text-xs tracking-[0.3em] shadow-2xl shadow-indigo-600/30 transition-all flex items-center justify-center group">
              {isSubmitting ? <RefreshCw className="w-6 h-6 animate-spin" /> : <>{authView === 'login' ? 'Authorize Access' : 'Initialize Node'} <LogIn className="w-5 h-5 ml-4 group-hover:translate-x-1 transition-transform" /></>}
            </button>
          </form>

          <button 
            onClick={() => setAuthView(authView === 'login' ? 'signup' : 'login')}
            className="mt-12 text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-indigo-400 transition-all text-center"
          >
            {authView === 'login' ? "নতুন অ্যাকাউন্ট তৈরি করতে চান? এখানে ক্লিক করুন" : "ইতিমধ্যে অ্যাকাউন্ট আছে? লগইন করুন"}
          </button>
        </div>
      </div>
    </div>
  );
};

