  Plus
} from 'lucide-react';
import { SubscriptionTier, UserProfile, StudioMode } from '../types';

type AdminTab = 'nodes' | 'intelligence' | 'revenue' | 'system';

interface AuditLog {
  id: string;
  timestamp: string;
  userEmail: string;
  action: string;
  status: 'Success' | 'Warning' | 'Critical';
  ip: string;
  product?: StudioMode;
}

interface Transaction {
  id: string;
  timestamp: string;
  userEmail: string;
  plan: SubscriptionTier;
  amount: number;
  status: 'Completed' | 'Refunded' | 'Pending';
}

interface StoredUser extends UserProfile {
  password?: string;
  signupDate?: string;
  lastActive?: string;
}

const AdminPanel: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AdminTab>('nodes');
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [showCreditModal, setShowCreditModal] = useState<{email: string, current: number} | null>(null);
  const [creditAmount, setCreditAmount] = useState<number>(500);
  const [showToast, setShowToast] = useState<{show: boolean, msg: string}>({show: false, msg: ''});

  const [users, setUsers] = useState<StoredUser[]>([]);
  const [logs, setLogs] = useState<AuditLog[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  const loadAdminData = () => {
    setIsRefreshing(true);
    const storedUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const storedLogs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const storedTransactions = JSON.parse(localStorage.getItem('lumina_transactions') || '[]');

    setUsers(storedUsers);
    setLogs(storedLogs.sort((a: any, b: any) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
    setTransactions(storedTransactions.sort((a: any, b: any) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));

    setTimeout(() => setIsRefreshing(false), 800);
  };

  useEffect(() => {
    loadAdminData();
  }, []);

  const stats = useMemo(() => {
    const totalRev = transactions.reduce((acc, curr) => acc + (curr.status === 'Completed' ? curr.amount : 0), 0);
    return [
      { label: 'Revenue Ledger', val: `₹${totalRev.toLocaleString()}`, change: '+14.2%', icon: DollarSign, color: 'text-emerald-400' },
      { label: 'Active Nodes', val: users.length.toString(), change: '+8.1%', icon: Cpu, color: 'text-blue-400' },
      { label: 'Neural Events', val: logs.length.toString(), change: '+32%', icon: Zap, color: 'text-amber-400' },
      { label: 'Database Sync', val: '99.9%', change: 'Optimal', icon: Database, color: 'text-indigo-400' },
    ];
  }, [users, logs, transactions]);

  const triggerToast = (msg: string) => {
    setShowToast({ show: true, msg });
    setTimeout(() => setShowToast({ show: false, msg: '' }), 3000);
  };

  const handleUpdatePlan = (email: string, newPlan: SubscriptionTier) => {
    const updated = users.map(u => u.email === email ? { ...u, plan: newPlan } : u);
    localStorage.setItem('lumina_users', JSON.stringify(updated));
    setUsers(updated);
    triggerToast(`Node ${email} escalated to ${newPlan}`);
  };

  const handleAddCredits = () => {
    if (!showCreditModal) return;
    const updated = users.map(u => u.email === showCreditModal.email ? { ...u, credits: (u.credits || 0) + creditAmount } : u);
    localStorage.setItem('lumina_users', JSON.stringify(updated));
    setUsers(updated);
    setShowCreditModal(null);
    triggerToast(`${creditAmount} Credits Injected into Node`);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700 pb-12">
