            {success && <div className="p-5 bg-emerald-500/10 border border-emerald-500/20 rounded-[1.5rem] text-emerald-500 text-xs font-black uppercase flex items-center"><CheckCircle2 className="w-5 h-5 mr-4" />{success}</div>}

            {authView === 'signup' && (
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Identity Name</label>
                <div className="relative group">
