} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode, TimelineLayer } from '../types';

interface VideoEditorProps {
  onSave: (project: Project) => void;
}

const VideoEditor: React.FC<VideoEditorProps> = ({ onSave }) => {
  const location = useLocation();
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [selectedLayerIds, setSelectedLayerIds] = useState<Set<string>>(new Set());
  const [isGeneratingScene, setIsGeneratingScene] = useState(false);
  const [scenePrompt, setScenePrompt] = useState("");
  const [generationStatus, setGenerationStatus] = useState("");
  const [layers, setLayers] = useState<TimelineLayer[]>([
    { id: '1', name: 'Intro Background', type: 'video', start: 0, duration: 100, content: 'https://picsum.photos/seed/studio/1280/720', volume: 100, opacity: 100, scale: 1, borderRadius: 0, locked: false, animation: 'none' },
    { id: '2', name: 'Primary Audio', type: 'audio', start: 0, duration: 80, content: 'bg-music', volume: 80, locked: false },
  ]);
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16' | '1:1'>('16:9');
  const [canvasColor, setCanvasColor] = useState('#020617');
  const [showSaveToast, setShowSaveToast] = useState(false);
  const [showGenerationModal, setShowGenerationModal] = useState(false);

  const uploadInputRef = useRef<HTMLInputElement>(null);
  const activeLayer = layers.find(l => selectedLayerIds.has(l.id)) || layers[0];

  useEffect(() => {
    // Read template data if navigated from Template Hub
    const state = location.state as { templateData?: any, isTemplate?: boolean };
    if (state?.isTemplate && state.templateData) {
      if (state.templateData.aspectRatio) setAspectRatio(state.templateData.aspectRatio);
      if (state.templateData.theme) setCanvasColor(state.templateData.theme === 'cyberpunk' ? '#1e1b4b' : '#020617');
      // Potential scene auto-prompt
      if (state.templateData.theme === 'cyberpunk') setScenePrompt("Cinematic neon cyberpunk city vlog background");
    }
  }, [location.state]);

  const updateLayer = (id: string, updates: Partial<TimelineLayer>) => {
    setLayers(prev => prev.map(l => l.id === id ? { ...l, ...updates } : l));
  };

  const handleGenerateAIScene = async () => {
    if (!scenePrompt) return;
    setIsGeneratingScene(true);
    setGenerationStatus("Initializing Veo Intelligence...");

    const gemini = GeminiService.getInstance();

    setTimeout(() => setGenerationStatus("Synthesizing Video Frames..."), 3000);
    setTimeout(() => setGenerationStatus("Merging Audio Waves..."), 8000);

    const videoUrl = await gemini.generateVideo(scenePrompt, aspectRatio === '9:16' ? '9:16' : '16:9');

    if (videoUrl) {
      const newLayer: TimelineLayer = {
        id: Date.now().toString(),
        name: `AI Scene: ${scenePrompt.slice(0, 15)}...`,
        type: 'video',
        start: 0,
        duration: 50,
        content: videoUrl,
        volume: 100,
        locked: false,
        animation: 'fade',
        scale: 1
      };
      setLayers([newLayer, ...layers]);
      setShowGenerationModal(false);
      setScenePrompt("");
    } else {
      setGenerationStatus("Neural Synthesis Failed. Check API limits.");
      setTimeout(() => setIsGeneratingScene(false), 2000);
    }

    setIsGeneratingScene(false);
  };

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500 overflow-hidden relative">
      <input type="file" ref={uploadInputRef} className="hidden" accept="video/*" onChange={(e) => {
        const file = e.target.files?.[0];
        if (file) setLayers([...layers, { id: Date.now().toString(), name: file.name, type: 'video', start: 0, duration: 50, content: URL.createObjectURL(file), volume: 100, locked: false, animation: 'none', scale: 1 }]);
      }} />

      {/* Veo Generation Modal */}
      {showGenerationModal && (
        <div className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-6 animate-in fade-in duration-300">
           <div className="w-full max-w-2xl bg-slate-900 border border-slate-800 rounded-[3rem] p-10 shadow-2xl relative overflow-hidden">
             <button onClick={() => setShowGenerationModal(false)} className="absolute top-8 right-8 p-3 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all">
               <X className="w-6 h-6" />
             </button>

             <div className="flex items-center space-x-4 mb-8">
               <div className="p-4 bg-indigo-600/20 rounded-2xl text-indigo-400">
                 <Film className="w-8 h-8" />
               </div>
               <div>
                 <h3 className="text-2xl font-black uppercase tracking-tight">Generate AI Scene</h3>
                 <p className="text-slate-500 text-sm">Powered by Veo 3.1 Neural Engine</p>
               </div>
             </div>

             <div className="space-y-6">
                <div className="relative">
                  <textarea 
                    value={scenePrompt}
                    onChange={(e) => setScenePrompt(e.target.value)}
                    placeholder="Describe your scene: 'A cinematic drone shot of a futuristic neon city at night'..."
                    className="w-full h-40 bg-slate-950 border border-slate-800 rounded-3xl p-6 text-slate-100 text-lg focus:ring-4 focus:ring-indigo-500/20 transition-all resize-none"
                  />
                  <div className="absolute bottom-4 right-4 flex items-center space-x-2 text-[10px] font-black uppercase text-slate-600">
                    <Cpu className="w-3 h-3" />
                    <span>Real-time Synthesis</span>
                  </div>
                </div>

                {isGeneratingScene ? (
                  <div className="flex flex-col items-center py-6 space-y-4">
                    <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
                      <div className="h-full bg-indigo-500 animate-progress-indeterminate" />
                    </div>
                    <p className="text-indigo-400 font-black uppercase tracking-[0.2em] text-[10px] animate-pulse">{generationStatus}</p>
                  </div>
                ) : (
                  <button 
                    onClick={handleGenerateAIScene}
                    disabled={!scenePrompt}
                    className="w-full py-5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-indigo-600/30 disabled:opacity-30 transition-all flex items-center justify-center"
                  >
                    <Sparkles className="w-5 h-5 mr-3" /> Initialize Video Synthesis
                  </button>
                )}
             </div>
           </div>
        </div>
      )}

      {showSaveToast && (
        <div className="fixed top-20 right-10 bg-emerald-600 text-white px-8 py-4 rounded-2xl shadow-2xl z-[100] animate-in slide-in-from-right">
          <CheckCircle className="w-5 h-5 mr-3 inline" />
          <span className="font-bold uppercase tracking-widest text-xs ml-2">Production Synced to Cloud</span>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-2">
