             <button onClick={() => setAspectRatio('9:16')} className={`px-4 py-2 text-[10px] font-black rounded-lg transition-all ${aspectRatio === '9:16' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-slate-300'}`}><Smartphone className="w-4 h-4" /></button>
          </div>
        </div>
        <div className="flex items-center space-x-3">
          <button 
            onClick={() => setShowGenerationModal(true)}
            className="flex items-center px-6 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/30 transition-all"
