            <div className="text-sm font-mono text-blue-400 bg-blue-500/10 px-4 py-1.5 rounded-xl border border-blue-500/20">00:00:{(currentTime % 60).toString().padStart(2, '0')}</div>
          </div>
          <div className="flex space-x-3">
            <button className="p-3 bg-slate-800 rounded-xl text-slate-400 hover:text-white transition-all"><RotateCcw className="w-5 h-5" /></button>
            <button 
              onClick={() => {
                const next = layers.filter(l => !selectedLayerIds.has(l.id));
                setLayers(next.length > 0 ? next : layers);
                setSelectedLayerIds(new Set());
              }}
              className="p-3 bg-slate-800 rounded-xl text-rose-500 hover:bg-rose-600 hover:text-white transition-all"
            >
              <Trash2 className="w-5 h-5" />
            </button>
          </div>
        </div>
        <div className="flex-1 space-y-4 overflow-y-auto pr-4 custom-scrollbar">
           {layers.map(layer => (
             <div 
              key={layer.id} 
              onClick={(e) => {
                if (e.metaKey || e.ctrlKey) {
                  const next = new Set(selectedLayerIds);
                  if (next.has(layer.id)) next.delete(layer.id); else next.add(layer.id);
                  setSelectedLayerIds(next);
                } else {
                  setSelectedLayerIds(new Set([layer.id]));
                }
              }}
              className={`flex items-center space-x-6 p-2 rounded-2xl transition-all cursor-pointer border ${selectedLayerIds.has(layer.id) ? 'bg-blue-600/10 border-blue-500/30' : 'border-transparent hover:bg-slate-800/50'}`}
             >
                <div className="w-48 truncate text-[10px] font-black text-slate-500 uppercase flex items-center">
                  {layer.locked && <Lock className="w-3 h-3 mr-3 text-rose-500" />}
                  {layer.name}
                </div>
                <div className={`flex-1 h-10 rounded-xl border border-white/5 shadow-inner flex items-center px-6 relative group/tl transition-all ${layer.type === 'audio' ? 'bg-indigo-600/20' : 'bg-rose-600/20'}`}>
                   {layer.type === 'audio' ? <Volume2 className="w-4 h-4 text-indigo-400" /> : <Film className="w-4 h-4 text-rose-400" />}
                   <div className="absolute inset-y-0 left-0 w-1 bg-white/20" />
                   <div className="absolute inset-y-0 right-0 w-3 bg-white/10 opacity-0 group-hover/tl:opacity-100 cursor-col-resize transition-opacity" />
                </div>
             </div>
           ))}
        </div>
      </div>
    </div>
  );
};

