import React, { useState, useRef, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import { 
  Paintbrush, Eraser, Square, Circle, Minus, Wand2, Save, Undo,
  Download, Sparkles, CheckCircle, Box, Layers, Palette, 
  Trash2, RotateCcw, Monitor, MousePointer2, Pencil, Shapes
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode } from '../types';

interface PaintStudioProps {
  onSave: (project: Project) => void;
}

type Tool = 'brush' | 'eraser' | 'shape';
type RenderStyle = '3d-disney' | '2d-anime' | '3d-realistic' | 'comic';

const PaintStudio: React.FC<PaintStudioProps> = ({ onSave }) => {
  const location = useLocation();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<Tool>('brush');
  const [color, setColor] = useState('#3b82f6');
  const [strokeWidth, setStrokeWidth] = useState(8);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [renderStyle, setRenderStyle] = useState<RenderStyle>('3d-disney');

  const lastPos = useRef<{ x: number, y: number } | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#020617';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
      }
    }

    // Read template data if navigated from Template Hub
    const state = location.state as { templateData?: any, isTemplate?: boolean };
    if (state?.isTemplate && state.templateData) {
      if (state.templateData.style) setRenderStyle(state.templateData.style);
    }
  }, [location.state]);

  const getMousePos = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.MouseEvent) => {
    setIsDrawing(true);
    lastPos.current = getMousePos(e);
  };

  const draw = (e: React.MouseEvent) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    const currentPos = getMousePos(e);
    ctx.beginPath();
    ctx.moveTo(lastPos.current!.x, lastPos.current!.y);
    ctx.lineTo(currentPos.x, currentPos.y);
    ctx.strokeStyle = tool === 'eraser' ? '#020617' : color;
    ctx.lineWidth = strokeWidth;
    ctx.stroke();
    lastPos.current = currentPos;
  };

  const stopDrawing = () => setIsDrawing(false);

  const handleSynthesizeCharacter = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();

    let styleInstruction = "";
    switch(renderStyle) {
      case '3d-disney': styleInstruction = "3D Pixar Disney style character, cinematic lighting, subsurface scattering, 8k render, Unreal Engine 5."; break;
      case '2d-anime': styleInstruction = "High-quality Studio Ghibli style anime character, expressive lines, vibrant watercolors."; break;
      case '3d-realistic': styleInstruction = "Hyper-realistic 3D character, detailed skin textures, realistic hair simulation, 8k octane render."; break;
      case 'comic': styleInstruction = "Modern Marvel style comic book art, bold inks, dynamic shading."; break;
    }

    const finalPrompt = `Professional character design asset based on the provided sketch: ${prompt}. ${styleInstruction}`;
    const result = await gemini.generateImage(finalPrompt, "1:1", true);

    if (result) {
      const img = new Image();
      img.onload = () => {
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx) {
          ctx.drawImage(img, 0, 0, canvasRef.current!.width, canvasRef.current!.height);
        }
      };
      img.src = result;
    }
    setIsGenerating(false);
  };

  const handleDownload = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      const link = document.createElement('a');
      link.href = canvas.toDataURL('image/png');
      link.download = `lumina-character-${Date.now()}.png`;
      link.click();
    }
  };

  return (
    <div className="h-full flex flex-col space-y-6 animate-in fade-in duration-500 max-w-7xl mx-auto pb-10">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black uppercase tracking-tight flex items-center">
            <Palette className="w-8 h-8 mr-4 text-emerald-500" /> Animation Character Studio
          </h2>
          <p className="text-slate-400 mt-2 font-medium italic">Hand-drawn sketches synthesized into pro animation assets.</p>
        </div>
        <div className="flex items-center space-x-3">
          <button onClick={() => {
            const ctx = canvasRef.current?.getContext('2d');
            if (ctx) { ctx.fillStyle = '#020617'; ctx.fillRect(0,0,1600,1200); }
          }} className="px-6 py-3 bg-slate-800 hover:bg-slate-700 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-300 border border-slate-700 transition-all"><RotateCcw className="w-4 h-4 mr-2 inline" /> Clear Canvas</button>
          <button onClick={handleDownload} className="px-6 py-3 bg-slate-800 hover:bg-slate-700 rounded-2xl text-[10px] font-black uppercase tracking-widest text-white border border-slate-700 transition-all"><Download className="w-4 h-4 mr-2 inline" /> Export PNG</button>
          <button onClick={handleSynthesizeCharacter} disabled={isGenerating || !prompt} className="px-10 py-3 bg-indigo-600 hover:bg-indigo-500 rounded-2xl text-[10px] font-black uppercase tracking-widest text-white shadow-xl shadow-indigo-600/30 transition-all disabled:opacity-50">
            <Sparkles className="w-4 h-4 mr-3 inline" /> Synthesize Character
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col lg:flex-row gap-8 min-h-0">
         <div className="w-full lg:w-24 bg-slate-900 border border-slate-800 rounded-[3rem] p-5 flex flex-row lg:flex-col items-center justify-center space-x-4 lg:space-x-0 lg:space-y-6 shadow-2xl">
            {[
              { id: 'brush', icon: Pencil, label: 'Sketch' },
              { id: 'eraser', icon: Eraser, label: 'Erase' },
              { id: 'shape', icon: Shapes, label: 'Blocks' }
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setTool(t.id as Tool)} 
                title={t.label}
                className={`p-4 rounded-2xl transition-all shadow-lg ${tool === t.id ? 'bg-indigo-600 text-white scale-110' : 'bg-slate-800 text-slate-500 hover:text-white'}`}
              >
                <t.icon className="w-6 h-6" />
              </button>
            ))}
            <div className="w-12 h-px bg-slate-800 my-4 hidden lg:block" />
            {['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#ffffff', '#000000'].map(c => (
              <button key={c} onClick={() => setColor(c)} className={`w-10 h-10 rounded-2xl border-2 transition-all hover:scale-110 ${color === c ? 'border-white scale-110 shadow-lg shadow-white/20' : 'border-transparent'}`} style={{ backgroundColor: c }} />
            ))}
         </div>

         <div className="flex-1 bg-slate-900 rounded-[3.5rem] border border-slate-800 p-8 flex flex-col shadow-2xl relative overflow-hidden">
            <div className="flex-1 bg-[#020617] rounded-[2.5rem] shadow-inner border border-white/5 overflow-hidden relative cursor-crosshair group">
               <canvas 
                ref={canvasRef} width={1600} height={1200}
                onMouseDown={startDrawing} onMouseMove={draw} onMouseUp={stopDrawing} onMouseLeave={stopDrawing}
                className="w-full h-full object-contain"
               />
               <div className="absolute top-6 right-6 flex items-center space-x-4 opacity-0 group-hover:opacity-100 transition-all">
                  <div className="px-4 py-2 bg-black/60 backdrop-blur-md rounded-xl border border-white/10 text-[9px] font-black uppercase tracking-widest text-slate-400">
                    <Monitor className="w-3.5 h-3.5 mr-2 inline" /> 1600 x 1200 Workspace
                  </div>
               </div>
               {isGenerating && (
                 <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-xl flex flex-col items-center justify-center z-50 animate-in fade-in duration-300">
                    <div className="w-20 h-20 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-8 shadow-2xl shadow-indigo-500/20" />
                    <p className="text-indigo-400 font-black uppercase tracking-[0.4em] text-xs animate-pulse">Synthesizing 3D Neural Mesh...</p>
                 </div>
               )}
            </div>

            <div className="mt-8 flex flex-col md:flex-row gap-6">
              <div className="flex-1 relative">
                <input 
                  value={prompt} onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Character metadata: 'A cybernetic warrior with glowing blue armor'..." 
                  className="w-full bg-slate-950 border border-slate-800 rounded-3xl py-5 px-8 focus:ring-4 focus:ring-indigo-500/10 text-slate-100 font-medium text-lg transition-all"
                />
                <Sparkles className="absolute right-6 top-1/2 -translate-y-1/2 w-6 h-6 text-indigo-500" />
              </div>
              <div className="flex bg-slate-950 border border-slate-800 p-1.5 rounded-3xl">
                {[
                  { id: '3d-disney', label: 'Pixar' },
                  { id: '2d-anime', label: 'Anime' },
                  { id: '3d-realistic', label: 'Realistic' }
                ].map(style => (
                  <button 
                    key={style.id} 
                    onClick={() => setRenderStyle(style.id as RenderStyle)}
                    className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${renderStyle === style.id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
                  >
                    {style.label}
                  </button>
                ))}
              </div>
            </div>
         </div>
      </div>
    </div>
  );
};

