import React, { useState, useEffect } from 'react';
import { 
  User, Mail, Lock, Sparkles, UserPlus, LogIn, Key, AlertCircle, Eye, EyeOff, 
  CheckCircle2, ChevronLeft, RefreshCw, Smartphone, Calendar, ShieldCheck,
  Cpu, Terminal, ShieldAlert
} from 'lucide-react';
import { UserProfile, SubscriptionTier } from '../types';

interface AuthProps {
  onLogin: (user: UserProfile) => void;
}

interface StoredUser extends UserProfile {
  password: string;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [authView, setAuthView] = useState<'login' | 'signup' | 'forgot'>('login');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    mobile: '',
    dob: '',
    password: ''
  });

  const getPasswordStrength = (pass: string) => {
    if (pass.length === 0) return 0;
    let score = 0;
    if (pass.length > 8) score++;
    if (/[A-Z]/.test(pass)) score++;
    if (/[0-9]/.test(pass)) score++;
    if (/[^A-Za-z0-9]/.test(pass)) score++;
    return score;
  };

  useEffect(() => {
    const existingUsers = localStorage.getItem('lumina_users');
    if (!existingUsers) {
      const defaultUsers: StoredUser[] = [
        {
          name: 'Master Admin',
          role: 'Studio Admin',
          avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=admin',
          email: 'admin@lumina.com',
          password: 'admin123',
          plan: 'Enterprise',
          credits: 99999,
          revenue: 0,
          referralCode: 'ADMIN-001',
          referralCount: 0,
          facebookConnected: false,
          githubConnected: false,
          twitterConnected: false,
          language: 'bn',
          studentVerificationStatus: 'verified',
          isApproved: true,
          isBlocked: false
        }
      ];
      localStorage.setItem('lumina_users', JSON.stringify(defaultUsers));
    }
  }, []);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    setIsSubmitting(true);

    const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');

    setTimeout(() => {
      setIsSubmitting(false);

      if (authView === 'login') {
        const user = users.find((u: any) => 
          (u.email.toLowerCase() === formData.email.toLowerCase() || (u.mobile && u.mobile === formData.email)) && 
          u.password === formData.password
        );

        if (!user) {
          setError("ইমেল/মোবাইল বা পাসওয়ার্ড ভুল।");
          return;
        }
        if (user.isBlocked) {
          setError("আপনার অ্যাকাউন্টটি ব্লক করা হয়েছে।");
          return;
        }

        const { password, ...userProfile } = user;
        localStorage.setItem('lumina_session', JSON.stringify(userProfile));
        onLogin(userProfile);

      } else if (authView === 'signup') {
        if (!formData.name || !formData.email || !formData.password) {
          setError("সবগুলো ঘর পূরণ করুন।");
          return;
        }

        if (users.some((u: any) => u.email.toLowerCase() === formData.email.toLowerCase())) {
          setError("এই ইমেলটি ইতিমধ্যে ব্যবহার করা হয়েছে।");
          return;
        }

        const newUser: StoredUser = {
          name: formData.name,
          role: 'Creative User',
          avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${formData.email}`,
          email: formData.email,
          mobile: formData.mobile,
          dob: formData.dob,
          password: formData.password,
          plan: 'Individual' as SubscriptionTier,
          credits: 500,
          revenue: 0,
          referralCode: `LUMINA-${Math.random().toString(36).substring(7).toUpperCase()}`,
          referralCount: 0,
          facebookConnected: false,
          githubConnected: false,
          twitterConnected: false,
          language: 'bn',
          studentVerificationStatus: 'none',
          isApproved: true,
          isBlocked: false
        };

        localStorage.setItem('lumina_users', JSON.stringify([...users, newUser]));
        setSuccess("অ্যাকাউন্ট তৈরি হয়েছে! এখন লগইন করুন।");
        setAuthView('login');
      } else if (authView === 'forgot') {
        const exists = users.some((u: any) => u.email.toLowerCase() === formData.email.toLowerCase());
        if (exists) {
          setSuccess("পাসওয়ার্ড রিসেট লিঙ্ক আপনার ইমেলে পাঠানো হয়েছে।");
        } else {
          setError("এই ইমেলটি আমাদের ডাটাবেসে পাওয়া যায়নি।");
        }
      }
    }, 800);
  };

  const strength = getPasswordStrength(formData.password);

  return (
    <div className="min-h-screen bg-[#020617] flex items-center justify-center p-6 relative overflow-hidden font-sans">
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/10 blur-[120px] rounded-full" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-indigo-600/10 blur-[120px] rounded-full" />

      <div className="w-full max-w-[1000px] grid grid-cols-1 lg:grid-cols-2 bg-slate-900/80 rounded-[4rem] border border-slate-800 shadow-2xl overflow-hidden backdrop-blur-xl animate-in zoom-in-95 duration-500">

        <div className="hidden lg:flex flex-col justify-between p-16 bg-gradient-to-b from-indigo-600/20 to-slate-900/40 border-r border-slate-800 relative overflow-hidden">
          <div>
            <div className="flex items-center space-x-4 mb-14">
              <div className="w-14 h-14 rounded-2xl flex items-center justify-center shadow-2xl bg-indigo-600">
                <Sparkles className="w-8 h-8 text-white" />
              </div>
              <h1 className="text-3xl font-black tracking-tighter uppercase text-white">Lumina <span className="text-indigo-400">Pro</span></h1>
            </div>
            <h2 className="text-6xl font-black leading-[0.95] mb-10 text-white tracking-tighter">
              Creative <span className="text-indigo-500">Intelligence.</span>
            </h2>
            <p className="text-slate-400 text-lg font-medium leading-relaxed max-w-sm">
              Your decentralized studio for high-fidelity media production.
            </p>
          </div>

          <div className="space-y-6">
             <div className="p-8 bg-black/40 rounded-[2.5rem] border border-white/5 flex items-center justify-between">
                <div>
                   <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Node Security Status</p>
                   <div className="flex items-center space-x-2">
                      <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                      <p className="text-[10px] font-black text-emerald-500 uppercase">Encrypted Protocol Active</p>
                   </div>
                </div>
                <ShieldCheck className="w-6 h-6 text-slate-700" />
             </div>
          </div>
        </div>

        <div className="p-12 md:p-16 flex flex-col justify-center overflow-y-auto max-h-[90vh] custom-scrollbar">
          <div className="mb-10 text-center">
            <h3 className="text-3xl font-black uppercase tracking-tighter text-white mb-2">
              {authView === 'login' ? 'Authorization' : authView === 'signup' ? 'Node Creation' : 'Recovery'}
            </h3>
            <p className="text-slate-500 font-medium text-sm">
              {authView === 'login' ? 'ইমেল বা মোবাইল দিয়ে লগইন করুন' : authView === 'signup' ? 'নতুন স্টুডিও মেম্বার হিসেবে যুক্ত হোন' : 'আপনার পাসওয়ার্ড পুনরুদ্ধার করুন'}
            </p>
          </div>

          <form onSubmit={handleAuth} className="space-y-6">
            {error && <div className="p-4 bg-rose-500/10 border border-rose-500/20 rounded-[1.2rem] text-rose-500 text-xs font-bold uppercase flex items-center"><AlertCircle className="w-4 h-4 mr-3" />{error}</div>}
            {success && <div className="p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-[1.2rem] text-emerald-500 text-xs font-bold uppercase flex items-center"><CheckCircle2 className="w-4 h-4 mr-3" />{success}</div>}

            {authView !== 'forgot' && (
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Identity Access</label>
                <div className="relative group">
                  <Mail className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 group-focus-within:text-indigo-500" />
                  <input required value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-4 pl-14 pr-6 text-white text-sm focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all" placeholder="ইমেল বা মোবাইল নম্বর" />
                </div>
              </div>
            )}

            {authView === 'signup' && (
              <>
                <div className="space-y-2">
                  <div className="relative group">
                    <User className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 group-focus-within:text-indigo-500" />
                    <input required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-4 pl-14 pr-6 text-white text-sm focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all" placeholder="পূর্ণ নাম" />
                  </div>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className="relative group">
                    <Smartphone className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 group-focus-within:text-indigo-500" />
                    <input value={formData.mobile} onChange={e => setFormData({...formData, mobile: e.target.value})} className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-4 pl-14 pr-6 text-white text-sm focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all" placeholder="মোবাইল (ঐচ্ছিক)" />
                  </div>
                  <div className="relative group">
                    <Calendar className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 group-focus-within:text-indigo-500" />
                    <input type="date" value={formData.dob} onChange={e => setFormData({...formData, dob: e.target.value})} className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-4 pl-14 pr-6 text-white text-sm focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all" />
                  </div>
                </div>
              </>
            )}

            {authView !== 'forgot' && (
              <div className="space-y-2">
                <div className="relative group">
                  <Lock className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 group-focus-within:text-indigo-500" />
                  <input required type={showPassword ? "text" : "password"} value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-4 pl-14 pr-16 text-white text-sm focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all" placeholder="পাসওয়ার্ড" />
                  <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-600 hover:text-white transition-colors">
                    {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                  </button>
                </div>
                {authView === 'signup' && formData.password.length > 0 && (
                  <div className="px-2 pt-1">
                    <div className="flex space-x-1 h-1.5">
                       {[1,2,3,4].map(idx => (
                         <div key={idx} className={`flex-1 rounded-full transition-all duration-500 ${strength >= idx ? (strength < 3 ? 'bg-amber-500' : 'bg-emerald-500') : 'bg-slate-800'}`} />
                       ))}
                    </div>
                    <p className="text-[8px] font-black uppercase text-slate-600 mt-2 tracking-widest">Password Strength: {strength < 2 ? 'Weak' : strength < 4 ? 'Moderate' : 'Strong'}</p>
                  </div>
                )}
              </div>
            )}

            {authView === 'forgot' && (
              <div className="space-y-2">
                 <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Registered Email</label>
                 <input value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full bg-slate-950/50 border border-slate-800 rounded-2xl py-4 px-6 text-white text-sm focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all" placeholder="your@email.com" />
              </div>
            )}

            {authView === 'login' && (
              <div className="flex justify-end">
                <button type="button" onClick={() => setAuthView('forgot')} className="text-[10px] font-black uppercase text-slate-500 hover:text-indigo-400 transition-colors">Forgot Password?</button>
              </div>
            )}

            <button disabled={isSubmitting} className="w-full py-4.5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-black uppercase text-xs tracking-[0.2em] shadow-xl shadow-indigo-600/20 transition-all flex items-center justify-center">
              {isSubmitting ? <RefreshCw className="w-5 h-5 animate-spin" /> : 
               <>{authView === 'login' ? 'Authorize Access' : authView === 'signup' ? 'Initialize Node' : 'Request Link'} <LogIn className="w-4 h-4 ml-3" /></>}
            </button>
          </form>

          <div className="mt-8 pt-8 border-t border-slate-800/50 text-center">
             {authView === 'login' ? (
                <button onClick={() => setAuthView('signup')} className="text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-indigo-400 transition-all">নতুন অ্যাকাউন্ট তৈরি করুন</button>
             ) : (
                <button onClick={() => setAuthView('login')} className="text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-indigo-400 transition-all flex items-center mx-auto"><ChevronLeft className="w-3 h-3 mr-2" /> লগইন পেজে ফিরে যান</button>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

