interface UserProfilePageProps {
  user: UserProfile;
  setUser: (u: UserProfile) => void;
  onLogout: () => void;
}

const UserProfilePage: React.FC<UserProfilePageProps> = ({ user, setUser, onLogout }) => {
  const navigate = useNavigate();
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState(user);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');
  const [isRequestingWithdrawal, setIsRequestingWithdrawal] = useState(false);

  const avatarInputRef = useRef<HTMLInputElement>(null);
  const t = translations[user.language];

  const triggerToast = (msg: string) => {
    setToastMsg(msg);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const result = ev.target?.result as string;
        setUser({ ...user, avatar: result });
        const session = JSON.parse(localStorage.getItem('lumina_session') || '{}');
        localStorage.setItem('lumina_session', JSON.stringify({ ...session, avatar: result }));
        triggerToast("Profile picture updated!");
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveProfile = () => {
    setUser(editForm);
    localStorage.setItem('lumina_session', JSON.stringify(editForm));

    // Update global users list
    const allUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const updatedUsers = allUsers.map((u: any) => u.email === user.email ? { ...u, ...editForm } : u);
    localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));

    setIsEditing(false);
    triggerToast("Identity parameters synchronized.");
  };

  const handleRequestWithdrawal = () => {
    if (!user.revenue || user.revenue < 500) {
        triggerToast('Minimum withdrawal ₹500 required.');
        return;
    }
    setIsRequestingWithdrawal(true);
    setTimeout(() => {
        const newRequest: WithdrawalRequest = {
            id: 'WR-' + Math.random().toString(36).substring(2, 7).toUpperCase(),
            userEmail: user.email,
            amount: user.revenue,
            status: 'pending',
            timestamp: Date.now()
        };
        const existing = JSON.parse(localStorage.getItem('lumina_withdrawals') || '[]');
        localStorage.setItem('lumina_withdrawals', JSON.stringify([newRequest, ...existing]));

        setIsRequestingWithdrawal(false);
        triggerToast('Withdrawal Protocol Initialized. Awaiting Admin Approval.');
    }, 1500);
  };

