          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-[10px]">{toastMsg}</span>
        </div>
      )}

      <div className="relative h-72 rounded-[4rem] overflow-hidden bg-gradient-to-br from-indigo-600 via-blue-700 to-black border border-white/10 shadow-2xl">
        <div className="absolute inset-0 bg-black/30 backdrop-blur-[2px]" />
        <div className="absolute top-10 right-10 flex space-x-2">
           <div className="px-5 py-2.5 bg-white/10 backdrop-blur-xl rounded-2xl border border-white/20 text-[10px] font-black uppercase tracking-widest text-white flex items-center shadow-2xl">
              <Terminal className="w-3.5 h-3.5 mr-2" /> Node Kernel v3.1
           </div>
        </div>
      </div>

      <div className="px-12 -mt-24 relative z-10">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-10">
          <div className="flex items-end space-x-12">
            <div 
              onClick={() => avatarInputRef.current?.click()}
              className="w-56 h-56 rounded-[4rem] bg-slate-900 border-[10px] border-slate-950 p-2 shadow-2xl overflow-hidden group relative cursor-pointer"
            >
              <img src={user.avatar} className="w-full h-full rounded-[3rem] object-cover transition-transform group-hover:scale-110 duration-500" alt="" />
              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-all">
                <Camera className="w-10 h-10 text-white" />
              </div>
              <input type="file" ref={avatarInputRef} className="hidden" accept="image/*" onChange={handleAvatarChange} />
            </div>
            <div className="pb-8">
