                        </>
                    )}
                 </div>

                 <button onClick={handlePublishCourse} className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 rounded-2xl text-xs font-black uppercase tracking-widest text-white shadow-xl">Authorize & Publish</button>
