}

const AdminPanel: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AdminTab>('ledger');
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [showToast, setShowToast] = useState<{show: boolean, msg: string}>({show: false, msg: ''});

  const [users, setUsers] = useState<StoredUser[]>([]);
  const [withdrawals, setWithdrawals] = useState<WithdrawalRequest[]>([]);

  const loadAdminData = () => {
    setIsRefreshing(true);
    const storedUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const storedWithdrawals = JSON.parse(localStorage.getItem('lumina_withdrawals') || '[]');

    setUsers(storedUsers);
    setWithdrawals(storedWithdrawals.sort((a: any, b: any) => b.timestamp - a.timestamp));

    setTimeout(() => setIsRefreshing(false), 800);
  };

  useEffect(() => {
    loadAdminData();
  }, []);

  const triggerToast = (msg: string) => {
    setShowToast({ show: true, msg });
    setTimeout(() => setShowToast({ show: false, msg: '' }), 3000);
  };

  const handleApproveWithdrawal = (id: string) => {
    const request = withdrawals.find(w => w.id === id);
    if (!request) return;

    const updatedWithdrawals = withdrawals.map(w => w.id === id ? { ...w, status: 'approved' as const } : w);
    localStorage.setItem('lumina_withdrawals', JSON.stringify(updatedWithdrawals));
    setWithdrawals(updatedWithdrawals);

    const allUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const updatedUsers = allUsers.map((u: any) => {
        if (u.email === request.userEmail) {
            return { ...u, revenue: (u.revenue || 0) - request.amount };
        }
        return u;
    });
    localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));
    setUsers(updatedUsers);

    triggerToast(`Payment Authorized: ${request.amount} for ${request.userEmail}`);
  };

  const stats = useMemo(() => {
    const totalRev = users.reduce((acc, curr) => acc + (curr.revenue || 0), 0);
    return [
      { label: 'Global Ledger', val: `₹${totalRev.toLocaleString()}`, change: '+14.2%', icon: DollarSign, color: 'text-emerald-400' },
      { label: 'Pending Payouts', val: withdrawals.filter(w => w.status === 'pending').length.toString(), change: 'Critical', icon: Clock, color: 'text-amber-400' },
      { label: 'Active Nodes', val: users.length.toString(), change: '+8.1%', icon: Cpu, color: 'text-blue-400' },
      { label: 'Kernel Status', val: 'Online', change: 'Stable', icon: Database, color: 'text-indigo-400' },
    ];
  }, [users, withdrawals]);

  // Secure Filtering for Search
  const filteredUsers = useMemo(() => {
    return users.filter(u => 
      u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      u.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (u.mobile && u.mobile.includes(searchQuery))
    );
  }, [users, searchQuery]);

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700 pb-12">
      {showToast.show && (
