            <p className="text-3xl font-black mt-1 tracking-tighter text-white">{s.val}</p>
            <div className="absolute top-10 right-10 text-[9px] font-black px-3 py-1 bg-white/5 text-slate-400 rounded-full border border-white/10 group-hover:bg-indigo-600 group-hover:text-white transition-all">
