               </button>
             </div>
             <div className="p-8">
               {withdrawals.length > 0 ? (
                 <div className="space-y-4">
                   {withdrawals.map(w => (
                     <div key={w.id} className="flex flex-col sm:flex-row items-center justify-between p-6 bg-slate-950/40 border border-slate-800 rounded-[2rem] group hover:border-emerald-500/30 transition-all gap-4">
