                             <DollarSign className="w-6 h-6" />
                           </div>
                           <div>
                              <p className="text-sm font-black text-white">{w.userEmail}</p>
                              <p className="text-[10px] text-slate-500 font-mono mt-0.5 uppercase">REQUEST: {w.id} • {new Date(w.timestamp).toLocaleDateString()}</p>
                           </div>
                        </div>
