import React, { useState, useRef, useEffect } from 'react';
import { 
  User, Mail, Shield, CreditCard, Share2, LogOut, Camera, 
  Globe, CheckCircle, Copy, Save, X, Zap, Sparkles, ArrowRight, 
  GraduationCap, Timer, Upload, ExternalLink, RefreshCw, ShieldAlert,
  Terminal, ShieldCheck, DollarSign, Wallet, History, AlertCircle,
  Calendar, Smartphone, Lock, Eye, EyeOff, Trash2, Key, Fingerprint
} from 'lucide-react';
import { UserProfile, SubscriptionTier, WithdrawalRequest } from '../types';
import { translations } from '../App';
import { useNavigate } from 'react-router-dom';

interface UserProfilePageProps {
  user: UserProfile;
  setUser: (u: UserProfile) => void;
  onLogout: () => void;
}

const UserProfilePage: React.FC<UserProfilePageProps> = ({ user, setUser, onLogout }) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'identity' | 'security' | 'wallet'>('identity');
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState(user);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');
  const [isRequestingWithdrawal, setIsRequestingWithdrawal] = useState(false);

  // Password Change State
  const [passForm, setPassForm] = useState({ current: '', new: '', confirm: '' });
  const [showPass, setShowPass] = useState(false);

  const avatarInputRef = useRef<HTMLInputElement>(null);

  const triggerToast = (msg: string) => {
    setToastMsg(msg);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  const getPasswordStrength = (pass: string) => {
    if (pass.length === 0) return 0;
    let score = 0;
    if (pass.length > 8) score++;
    if (/[A-Z]/.test(pass)) score++;
    if (/[0-9]/.test(pass)) score++;
    if (/[^A-Za-z0-9]/.test(pass)) score++;
    return score;
  };

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const result = ev.target?.result as string;
        const updated = { ...user, avatar: result };
        setUser(updated);
        localStorage.setItem('lumina_session', JSON.stringify(updated));

        // Update in global users list
        const allUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
        const updatedUsers = allUsers.map((u: any) => u.email === user.email ? { ...u, avatar: result } : u);
        localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));

        triggerToast("Profile picture synchronized.");
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveProfile = () => {
    setUser(editForm);
    localStorage.setItem('lumina_session', JSON.stringify(editForm));

