  const [searchQuery, setSearchQuery] = useState('');
  const [showToast, setShowToast] = useState<{show: boolean, msg: string}>({show: false, msg: ''});

  const [users, setUsers] = useState<StoredUser[]>([]);
  const [withdrawals, setWithdrawals] = useState<WithdrawalRequest[]>([]);

  const loadAdminData = () => {
    setIsRefreshing(true);
    const storedUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const storedWithdrawals = JSON.parse(localStorage.getItem('lumina_withdrawals') || '[]');

    setUsers(storedUsers);
    setWithdrawals(storedWithdrawals.sort((a: any, b: any) => b.timestamp - a.timestamp));

    setTimeout(() => setIsRefreshing(false), 800);
  };

  useEffect(() => {
    loadAdminData();
  }, []);

  const triggerToast = (msg: string) => {
    setShowToast({ show: true, msg });
    setTimeout(() => setShowToast({ show: false, msg: '' }), 3000);
  };

  const handleApproveWithdrawal = (id: string) => {
    const updatedWithdrawals = withdrawals.map(w => w.id === id ? { ...w, status: 'approved' as const } : w);
    localStorage.setItem('lumina_withdrawals', JSON.stringify(updatedWithdrawals));
    setWithdrawals(updatedWithdrawals);
    triggerToast("Payment Transaction Authorized.");
  };

  const handleBlockUser = (email: string) => {
    const allUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const updatedUsers = allUsers.map((u: any) => u.email === email ? { ...u, isBlocked: !u.isBlocked } : u);
    localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));
    setUsers(updatedUsers);
    triggerToast("User Access Status Updated.");
  };

  // ADVANCED SEARCH FILTERING LOGIC
  const filteredUsers = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return users;

    return users.filter(u => 
      u.name.toLowerCase().includes(query) || 
      u.email.toLowerCase().includes(query) ||
      (u.mobile && u.mobile.includes(query))
    );
  }, [users, searchQuery]);

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700 pb-12">
      {showToast.show && (
        <div className="fixed top-24 right-10 bg-indigo-600 text-white px-8 py-4 rounded-2xl shadow-2xl z-[110] flex items-center animate-in slide-in-from-right duration-300 border border-white/20">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-[10px]">{showToast.msg}</span>
        </div>
      )}

