import { UserProfile } from '../types';
import { translations } from '../App';

interface HeaderProps {
  user: UserProfile;
  onLogout: () => void;
  setLanguage: (lang: 'en' | 'bn' | 'hi') => void;
  onElevate: () => void;
}

const Header: React.FC<HeaderProps> = ({ user, onLogout, setLanguage, onElevate }) => {
  const navigate = useNavigate();
  const [showLangMenu, setShowLangMenu] = useState(false);
  const [searchVal, setSearchVal] = useState("");
  const [isElevating, setIsElevating] = useState(false);
  const t = translations[user.language];

  const languages = [
    { code: 'en', label: 'English', flag: '🇺🇸' },
    { code: 'bn', label: 'বাংলা', flag: '🇧🇩' },
    { code: 'hi', label: 'हिन्दी', flag: '🇮🇳' }
  ];

  const handleSearch = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      const query = searchVal.trim().toUpperCase();
      if (query === 'LUMINA-SYS-ROOT') {
        setIsElevating(true);
        setSearchVal("");
        // Simulate high-security authentication
        setTimeout(() => {
          onElevate();
          setIsElevating(false);
          navigate('/admin');
        }, 1500);
      }
    }
  };

  const isCommandMode = searchVal.toUpperCase().startsWith('LUMINA-');

  return (
    <header className="h-20 border-b border-slate-800 bg-slate-950/80 backdrop-blur-xl flex items-center justify-between px-8 sticky top-0 z-40">
      <div className="flex-1 max-w-2xl relative group">
        <div className={`absolute left-5 top-1/2 -translate-y-1/2 transition-colors duration-300 ${isElevating ? 'text-rose-500 animate-pulse' : isCommandMode ? 'text-indigo-400' : 'text-slate-500'}`}>
          {isCommandMode ? <Terminal className="w-4 h-4" /> : <Search className="w-4 h-4" />}
        </div>

        <input 
          type="text" 
          value={searchVal}
          onChange={(e) => setSearchVal(e.target.value)}
          onKeyDown={handleSearch}
          placeholder={isElevating ? "EXECUTING ROOT ELEVATION..." : "Search projects or enter command..."} 
          className={`w-full bg-slate-900 border rounded-2xl py-3.5 pl-14 pr-12 text-xs transition-all duration-500 font-bold tracking-widest uppercase ${
            isElevating 
            ? 'border-rose-500 shadow-[0_0_30px_rgba(244,63,94,0.3)] text-rose-500 bg-black' 
            : isCommandMode 
            ? 'border-indigo-500/50 shadow-[0_0_20px_rgba(99,102,241,0.1)] text-indigo-400 bg-slate-950' 
            : 'border-slate-800 focus:border-indigo-500/50 text-slate-100 placeholder:text-slate-700'
          }`}
        />

        {searchVal && (
          <button onClick={() => setSearchVal("")} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-600 hover:text-white transition-colors">
            <X className="w-4 h-4" />
          </button>
        )}

        {isCommandMode && !isElevating && (
          <div className="absolute -bottom-8 left-4 flex items-center space-x-2 animate-in slide-in-from-top-2">
             <Cpu className="w-3 h-3 text-indigo-500" />
             <span className="text-[8px] font-black text-indigo-500 tracking-[0.3em]">System Command Mode Active</span>
          </div>
        )}
      </div>

      <div className="flex items-center space-x-6 ml-6">
        {user.role === 'Studio Admin' && (
          <div className="hidden lg:flex items-center px-5 py-2 bg-rose-500/10 border border-rose-500/20 rounded-xl text-[9px] font-black text-rose-500 uppercase tracking-[0.2em] animate-pulse">
            <ShieldAlert className="w-3.5 h-3.5 mr-2" />
            Superuser Active
          </div>
        )}

        <div className="relative">
          <button 
            onClick={() => setShowLangMenu(!showLangMenu)}
            className="flex items-center space-x-3 px-4 py-2 bg-slate-900 border border-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-white transition-all shadow-lg"
          >
            <Globe className="w-4 h-4" />
            <span>{languages.find(l => l.code === user.language)?.label}</span>
            <ChevronDown className={`w-3 h-3 transition-transform ${showLangMenu ? 'rotate-180' : ''}`} />
          </button>

          {showLangMenu && (
            <div className="absolute top-full right-0 mt-3 w-44 bg-slate-900 border border-slate-800 rounded-[1.5rem] shadow-2xl p-2 animate-in fade-in zoom-in-95 duration-200 z-50">
              {languages.map(lang => (
                <button
                  key={lang.code}
                  onClick={() => {
                    setLanguage(lang.code as any);
                    setShowLangMenu(false);
                  }}
                  className={`w-full flex items-center space-x-3 p-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${user.language === lang.code ? 'bg-indigo-600 text-white shadow-lg' : 'hover:bg-slate-800 text-slate-500 hover:text-white'}`}
                >
                  <span className="text-sm">{lang.flag}</span>
                  <span>{lang.label}</span>
                </button>
              ))}
            </div>
          )}
        </div>

        <button className="p-3 text-slate-500 hover:text-white bg-slate-900 border border-slate-800 rounded-xl transition-all relative group">
          <Bell className="w-5 h-5" />
          <span className="absolute top-2.5 right-2.5 w-2 h-2 bg-rose-500 rounded-full border-2 border-slate-950"></span>
        </button>

        <div className="h-8 w-px bg-slate-800" />

        <div 
          onClick={() => navigate('/profile')}
          className="flex items-center space-x-4 cursor-pointer group"
        >
          <div className="text-right hidden sm:block">
            <p className="text-xs font-black group-hover:text-indigo-400 transition-colors uppercase tracking-tight">{user.name}</p>
            <p className="text-[9px] text-slate-600 font-black tracking-widest uppercase">{user.plan} Account</p>
          </div>
          <div className={`w-11 h-11 rounded-2xl bg-slate-800 border-2 p-0.5 overflow-hidden transition-all group-hover:scale-105 shadow-xl ${user.role === 'Studio Admin' ? 'border-rose-500 shadow-rose-500/20' : 'border-indigo-500 shadow-indigo-500/20'}`}>
            <img src={user.avatar} alt="Avatar" className="w-full h-full rounded-xl object-cover" />
          </div>
        </div>
      </div>
    </header>
  );
};

