import React, { useState, useRef } from 'react';
import { 
  User, Mail, ShieldCheck, Wallet, History, Smartphone, Calendar, 
  Lock, Eye, EyeOff, Trash2, Key, Fingerprint, Camera, LogOut, 
  ChevronRight, ArrowRight, Zap, Sparkles, Terminal, Shield, 
  CheckCircle, RefreshCw, Smartphone as MobileIcon, UserCheck, 
  ShieldAlert, Database, Network, DollarSign
} from 'lucide-react';
import { UserProfile, WithdrawalRequest } from '../types';
import { useNavigate } from 'react-router-dom';

interface UserProfilePageProps {
  user: UserProfile;
  setUser: (u: UserProfile) => void;
  onLogout: () => void;
}

const UserProfilePage: React.FC<UserProfilePageProps> = ({ user, setUser, onLogout }) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'identity' | 'security' | 'wallet'>('identity');
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState(user);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');

  // Password State
  const [passForm, setPassForm] = useState({ current: '', new: '', confirm: '' });
  const [showPass, setShowPass] = useState(false);

  const avatarInputRef = useRef<HTMLInputElement>(null);

  const triggerToast = (msg: string) => {
    setToastMsg(msg);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const result = ev.target?.result as string;
        const updated = { ...user, avatar: result };
        setUser(updated);
        localStorage.setItem('lumina_session', JSON.stringify(updated));

        const allUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
        const updatedUsers = allUsers.map((u: any) => u.email === user.email ? { ...u, avatar: result } : u);
        localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));

        triggerToast("Profile identity image synchronized.");
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveProfile = () => {
    setUser(editForm);
    localStorage.setItem('lumina_session', JSON.stringify(editForm));

    const allUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const updatedUsers = allUsers.map((u: any) => u.email === user.email ? { ...u, ...editForm } : u);
    localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));

    setIsEditing(false);
    triggerToast("Identity parameters updated.");
  };

  return (
    <div className="max-w-7xl mx-auto space-y-10 animate-in fade-in duration-700 pb-20 relative">
      {showToast && (
        <div className="fixed top-24 right-10 bg-indigo-600 text-white px-8 py-4 rounded-2xl shadow-2xl z-[120] flex items-center animate-in slide-in-from-right duration-300 border border-white/10">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-[10px]">{toastMsg}</span>
        </div>
      )}

      {/* Hero Banner Area */}
      <div className="relative h-80 rounded-[4rem] overflow-hidden border border-white/5 shadow-2xl group">
        <div className="absolute inset-0 bg-gradient-to-br from-indigo-900 via-[#020617] to-black" />
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-20 mix-blend-overlay" />

        <div className="absolute top-10 right-10 flex space-x-4">
           <div className="px-6 py-3 bg-white/5 backdrop-blur-2xl rounded-2xl border border-white/10 text-[9px] font-black uppercase tracking-[0.4em] text-slate-400 flex items-center shadow-2xl">
              <Network className="w-4 h-4 mr-3 text-indigo-400" /> Neural Uplink Active
           </div>
           {user.role === 'Studio Admin' && (
             <div className="px-6 py-3 bg-rose-500/10 backdrop-blur-2xl rounded-2xl border border-rose-500/20 text-[9px] font-black uppercase tracking-[0.4em] text-rose-500 flex items-center shadow-2xl animate-pulse">
                <ShieldAlert className="w-4 h-4 mr-3" /> Root Access
             </div>
           )}
        </div>

        <div className="absolute inset-x-16 bottom-12 flex flex-col md:flex-row items-center md:items-end justify-between gap-10">
           <div className="flex flex-col md:flex-row items-center md:items-end md:space-x-12">
