        <div className="fixed top-24 right-10 bg-indigo-600 text-white px-8 py-4 rounded-2xl shadow-2xl z-[150] flex items-center animate-in slide-in-from-right duration-300 border border-white/20">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-[10px]">{showToast.msg}</span>
        </div>
      )}

