              <div className="flex items-center space-x-4 mt-3">
                <span className="px-4 py-1.5 bg-slate-900 border border-slate-800 rounded-lg text-[9px] font-black text-slate-500 uppercase tracking-[0.2em]">Root Core v3.1</span>
