import React, { useState, useEffect } from 'react';
import { Search, Bell, Globe, ChevronDown, Terminal, ShieldAlert, X, Cpu, Lock } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { UserProfile } from '../types';
import { translations } from '../App';

interface HeaderProps {
  user: UserProfile;
  onLogout: () => void;
  setLanguage: (lang: 'en' | 'bn' | 'hi') => void;
  onElevate: () => void;
}

const Header: React.FC<HeaderProps> = ({ user, onLogout, setLanguage, onElevate }) => {
  const navigate = useNavigate();
  const [showLangMenu, setShowLangMenu] = useState(false);
  const [searchVal, setSearchVal] = useState("");
  const [isElevating, setIsElevating] = useState(false);
  const t = translations[user.language];

  const languages = [
    { code: 'en', label: 'English', flag: '🇺🇸' },
    { code: 'bn', label: 'বাংলা', flag: '🇧🇩' },
    { code: 'hi', label: 'हिन्दी', flag: '🇮🇳' }
  ];

  const handleSearch = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      const query = searchVal.trim().toUpperCase();
      if (query === 'LUMINA-SYS-ROOT') {
        setIsElevating(true);
        setSearchVal("");
        // Simulate terminal-style high-security authentication
        setTimeout(() => {
          onElevate();
          setIsElevating(false);
          navigate('/admin');
        }, 1200);
      }
    }
  };

  const isCommandMode = searchVal.toUpperCase().startsWith('LUMINA-');

  return (
    <header className="h-20 border-b border-slate-800 bg-slate-950/80 backdrop-blur-2xl flex items-center justify-between px-8 sticky top-0 z-40">
      <div className="flex-1 max-w-2xl relative group">
        <div className={`absolute left-6 top-1/2 -translate-y-1/2 transition-all duration-300 ${isElevating ? 'text-rose-500 animate-pulse' : isCommandMode ? 'text-rose-500' : 'text-slate-500'}`}>
          {isCommandMode ? <Terminal className="w-5 h-5" /> : <Search className="w-4 h-4" />}
        </div>

        <input 
          type="text" 
          value={searchVal}
          onChange={(e) => setSearchVal(e.target.value)}
          onKeyDown={handleSearch}
          placeholder={isElevating ? "AUTHORIZING ROOT IDENTITY..." : "Search projects or enter master command..."} 
          className={`w-full bg-slate-900 border rounded-[1.2rem] py-4 pl-16 pr-12 text-xs transition-all duration-500 font-bold tracking-[0.2em] uppercase ${
            isElevating 
            ? 'border-rose-500 shadow-[0_0_40px_rgba(225,29,72,0.3)] text-rose-500 bg-black' 
            : isCommandMode 
            ? 'border-rose-500/50 shadow-[0_0_20px_rgba(225,29,72,0.1)] text-rose-500 bg-slate-950' 
            : 'border-slate-800 focus:border-indigo-500/50 text-slate-100 placeholder:text-slate-800'
          }`}
        />

        {searchVal && (
          <button onClick={() => setSearchVal("")} className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-700 hover:text-white transition-colors">
            <X className="w-4 h-4" />
          </button>
        )}

        {isCommandMode && !isElevating && (
          <div className="absolute -bottom-8 left-6 flex items-center space-x-2 animate-in slide-in-from-top-2 duration-300">
             <div className="w-2 h-2 rounded-full bg-rose-500 animate-pulse" />
             <span className="text-[8px] font-black text-rose-500 tracking-[0.3em] uppercase">Security Override Mode</span>
          </div>
        )}
      </div>

      <div className="flex items-center space-x-6 ml-8">
        {user.role === 'Studio Admin' && (
          <div className="hidden lg:flex items-center px-6 py-2.5 bg-rose-500/10 border border-rose-500/20 rounded-xl text-[9px] font-black text-rose-500 uppercase tracking-[0.3em] animate-pulse shadow-xl shadow-rose-900/10">
            <ShieldAlert className="w-4 h-4 mr-3" />
            Root Node Active
          </div>
        )}

        <div className="relative">
          <button 
            onClick={() => setShowLangMenu(!showLangMenu)}
            className="flex items-center space-x-3 px-5 py-2.5 bg-slate-900 border border-slate-800 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-white transition-all shadow-xl"
          >
            <Globe className="w-4 h-4" />
            <span>{languages.find(l => l.code === user.language)?.label}</span>
            <ChevronDown className={`w-3.5 h-3.5 transition-transform ${showLangMenu ? 'rotate-180' : ''}`} />
          </button>

          {showLangMenu && (
            <div className="absolute top-full right-0 mt-4 w-48 bg-slate-900 border border-slate-800 rounded-[1.8rem] shadow-2xl p-3 animate-in fade-in zoom-in-95 duration-200 z-50">
              {languages.map(lang => (
                <button
                  key={lang.code}
                  onClick={() => {
                    setLanguage(lang.code as any);
                    setShowLangMenu(false);
                  }}
                  className={`w-full flex items-center space-x-4 p-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${user.language === lang.code ? 'bg-indigo-600 text-white shadow-xl' : 'hover:bg-slate-800 text-slate-500 hover:text-white'}`}
                >
                  <span className="text-base">{lang.flag}</span>
                  <span>{lang.label}</span>
                </button>
              ))}
            </div>
          )}
        </div>

        <button className="p-3.5 text-slate-500 hover:text-white bg-slate-900 border border-slate-800 rounded-xl transition-all relative group shadow-xl">
          <Bell className="w-5 h-5" />
          <span className="absolute top-3 right-3 w-2.5 h-2.5 bg-rose-600 rounded-full border-2 border-slate-950 shadow-[0_0_10px_rose]"></span>
        </button>

        <div className="h-10 w-px bg-slate-800" />

        <div 
          onClick={() => navigate('/profile')}
          className="flex items-center space-x-5 cursor-pointer group"
        >
          <div className="text-right hidden sm:block">
            <p className="text-xs font-black group-hover:text-indigo-400 transition-colors uppercase tracking-tight">{user.name}</p>
            <p className="text-[9px] text-slate-700 font-black tracking-widest uppercase mt-0.5">{user.plan} Account</p>
          </div>
          <div className={`w-12 h-12 rounded-[1.2rem] bg-slate-800 border-2 p-1 overflow-hidden transition-all group-hover:scale-110 shadow-2xl ${user.role === 'Studio Admin' ? 'border-rose-500 shadow-rose-500/30' : 'border-indigo-600 shadow-indigo-600/30'}`}>
            <img src={user.avatar} alt="Avatar" className="w-full h-full rounded-[0.8rem] object-cover" />
          </div>
        </div>
      </div>
    </header>
  );
};

