    const storedWithdrawals = JSON.parse(localStorage.getItem('lumina_withdrawals') || '[]');

    setUsers(storedUsers);
    setWithdrawals(storedWithdrawals.sort((a: any, b: any) => b.timestamp - a.timestamp));

    setTimeout(() => setIsRefreshing(false), 800);
  };

  useEffect(() => {
    loadAdminData();
    const interval = setInterval(() => {
      setSystemStats(prev => ({
        ...prev,
        cpu: Math.floor(Math.random() * 20) + 30,
        traffic: prev.traffic + Math.floor(Math.random() * 5)
      }));
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  const triggerToast = (msg: string) => {
    setShowToast({ show: true, msg });
    setTimeout(() => setShowToast({ show: false, msg: '' }), 3000);
  };

  const handleUpdateConfig = (newConfig: Partial<SiteConfig>) => {
    const updated = { ...siteConfig, ...newConfig };
    setSiteConfig(updated);
    localStorage.setItem('lumina_site_config', JSON.stringify(updated));
    triggerToast("সিস্টেম কনফিগারেশন আপডেট করা হয়েছে।");
  };

  const toggleModule = (module: keyof SiteConfig['activeModules']) => {
    const updatedModules = { ...siteConfig.activeModules, [module]: !siteConfig.activeModules[module] };
    handleUpdateConfig({ activeModules: updatedModules });
  };

  const handleApproveWithdrawal = (id: string) => {
    const updatedWithdrawals = withdrawals.map(w => w.id === id ? { ...w, status: 'approved' as const } : w);
    localStorage.setItem('lumina_withdrawals', JSON.stringify(updatedWithdrawals));
    setWithdrawals(updatedWithdrawals);
    triggerToast("টাকা তোলার রিকোয়েস্ট এপ্রুভ করা হয়েছে।");
  };

  const handleBlockUser = (email: string) => {
    const allUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const updatedUsers = allUsers.map((u: any) => u.email === email ? { ...u, isBlocked: !u.isBlocked } : u);
    localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));
    setUsers(updatedUsers);
    triggerToast("ইউজারের এক্সেস পরিবর্তন করা হয়েছে।");
  };

  const filteredUsers = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return users;
    return users.filter(u => 
      u.name.toLowerCase().includes(query) || 
      u.email.toLowerCase().includes(query) ||
      (u.mobile && u.mobile.includes(query))
    );
  }, [users, searchQuery]);

  return (
    <div className="max-w-7xl mx-auto space-y-10 animate-in fade-in duration-700 pb-20">
      {showToast.show && (
        <div className="fixed top-24 right-10 bg-rose-600 text-white px-8 py-4 rounded-2xl shadow-2xl z-[150] flex items-center animate-in slide-in-from-right duration-300 border border-white/20">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-[10px]">{showToast.msg}</span>
        </div>
      )}

      {/* Admin Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-8">
        <div className="flex items-center space-x-8">
           <div className="w-20 h-20 bg-rose-600/10 rounded-[2.5rem] border border-rose-500/30 flex items-center justify-center text-rose-500 shadow-2xl animate-pulse">
              <ShieldAlert className="w-10 h-10" />
           </div>
           <div>
              <h2 className="text-5xl font-black tracking-tighter uppercase text-white leading-none">Control <span className="text-rose-500">Center</span></h2>
              <div className="flex items-center space-x-4 mt-3">
                <span className="px-4 py-1.5 bg-slate-900 border border-slate-800 rounded-lg text-[9px] font-black text-slate-500 uppercase tracking-[0.2em]">Root Core v4.0</span>
                <div className="flex items-center space-x-2">
                   <div className="w-2 h-2 rounded-full bg-emerald-500 shadow-[0_0_10px_emerald]" />
                   <span className="text-[9px] font-black text-emerald-500 uppercase">A to Z Authority Active</span>
                </div>
              </div>
           </div>
        </div>

        <div className="flex bg-slate-900 border border-slate-800 p-2 rounded-[2.5rem] shadow-2xl">
          {[
            { id: 'nodes', label: 'Users', icon: Users },
            { id: 'ledger', label: 'Finance', icon: DollarSign },
            { id: 'security', label: 'Logs', icon: Lock },
            { id: 'system', label: 'Control', icon: CloudCog }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`px-8 py-3.5 rounded-[1.8rem] text-[10px] font-black uppercase tracking-widest transition-all flex items-center whitespace-nowrap ${
                activeTab === tab.id ? 'bg-rose-600 text-white shadow-xl shadow-rose-600/20' : 'text-slate-500 hover:text-white'
              }`}
            >
              <tab.icon className="w-4 h-4 mr-3" /> {tab.label}
            </button>
          ))}
        </div>
      </div>

