                 <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mt-1">Authorized Access Layer - Zero Trust Protocol</p>
              </div>
           </div>

           {activeTab === 'nodes' && (
             <div className="relative group w-full md:w-[400px]">
