                   </div>
                </div>
             </div>
           )}

           {activeTab === 'security' && (
             <div className="p-16 animate-in fade-in duration-500">
                <div className="bg-slate-950/40 border border-slate-800 p-12 rounded-[4rem] space-y-10">
