                      {[
                        { time: '14:22:01', event: 'ADMIN ELEVATION ATTEMPT', status: 'SUCCESS', ip: '127.0.0.1' },
                        { time: '13:45:12', event: 'USER BLOCK EXECUTION', status: 'SUCCESS', ip: '127.0.0.1' },
                        { time: '12:10:55', event: 'MODULE DISABLE: PAINT', status: 'SUCCESS', ip: '127.0.0.1' }
                      ].map((log, i) => (
