                           <div>
                              <p className="text-[11px] font-black text-white uppercase">{log.event}</p>
                              <p className="text-[9px] text-slate-600 font-mono mt-1 uppercase">IP: {log.ip} • TIME: {log.time}</p>
                           </div>
                           <span className="text-[9px] font-black text-emerald-500 uppercase px-3 py-1 bg-emerald-500/10 rounded-lg">{log.status}</span>
                        </div>
                      ))}
                   </div>
                </div>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

