        const result = ev.target?.result as string;
        const updated = { ...user, avatar: result };
        setUser(updated);
        localStorage.setItem('lumina_session', JSON.stringify(updated));

        const allUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
        const updatedUsers = allUsers.map((u: any) => u.email === user.email ? { ...u, avatar: result } : u);
        localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));

        triggerToast("Profile identity image synchronized.");
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveProfile = () => {
    setUser(editForm);
    localStorage.setItem('lumina_session', JSON.stringify(editForm));

    const allUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
