const express = require('express');
const cors = require('cors');
const jwt = require('jsonwebtoken');
const bcrypt = require('bcryptjs');
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 5000;
const SECRET_KEY = process.env.JWT_SECRET || 'lumina-super-secret-key-2025';

app.use(cors());
app.use(express.json());

// In-memory "Database" for demonstration (In production, use MongoDB or PostgreSQL)
let users = [];
let siteConfig = {
  maintenanceMode: false,
  activeModules: { video: true, photo: true, paint: true, ads: true, office: true, shop: true },
  globalAnnouncement: ""
};
let withdrawals = [];

// --- MIDDLEWARE ---

const verifyToken = (req, res, next) => {
  const token = req.headers['authorization']?.split(' ')[1];
  if (!token) return res.status(403).json({ message: 'No token provided.' });

  jwt.verify(token, SECRET_KEY, (err, decoded) => {
    if (err) return res.status(401).json({ message: 'Failed to authenticate token.' });
    req.userId = decoded.id;
    req.userRole = decoded.role;
    next();
  });
};

const isAdmin = (req, res, next) => {
  if (req.userRole !== 'Studio Admin') return res.status(403).json({ message: 'Require Admin Role!' });
  next();
};

// --- ROUTES ---

// Auth: Signup
app.post('/api/auth/signup', async (req, res) => {
  const { name, email, password, mobile, dob } = req.body;

  if (users.find(u => u.email === email)) {
    return res.status(400).json({ message: 'User already exists.' });
  }

  const hashedPassword = await bcrypt.hash(password, 10);
  const newUser = {
    id: Date.now(),
    name,
    email,
    password: hashedPassword,
    mobile,
    dob,
    role: 'Creative User',
    credits: 500,
    revenue: 0,
    isBlocked: false,
    plan: 'Individual'
  };

  users.push(newUser);
  res.status(201).json({ message: 'User registered successfully.' });
});

// Auth: Login
app.post('/api/auth/login', async (req, res) => {
  const { email, password } = req.body;
  const user = users.find(u => u.email === email || u.mobile === email);

  if (!user) return res.status(404).json({ message: 'User not found.' });
  if (user.isBlocked) return res.status(403).json({ message: 'Account is blocked.' });

  const passwordIsValid = await bcrypt.compare(password, user.password);
  if (!passwordIsValid) return res.status(401).json({ message: 'Invalid password.' });

  const token = jwt.sign({ id: user.id, role: user.role }, SECRET_KEY, { expiresIn: '24h' });

  const { password: _, ...userProfile } = user;
  res.status(200).json({ token, user: userProfile });
});

// Admin: Get Users
app.get('/api/admin/users', [verifyToken, isAdmin], (req, res) => {
  const safeUsers = users.map(({ password, ...rest }) => rest);
  res.json(safeUsers);
});

// Admin: Update Site Config
app.post('/api/admin/config', [verifyToken, isAdmin], (req, res) => {
  siteConfig = { ...siteConfig, ...req.body };
  res.json({ message: 'Config updated.', config: siteConfig });
});

// Admin: Block/Unblock User
app.post('/api/admin/users/block', [verifyToken, isAdmin], (req, res) => {
  const { email } = req.body;
  users = users.map(u => u.email === email ? { ...u, isBlocked: !u.isBlocked } : u);
  res.json({ message: 'User status updated.' });
});

app.listen(PORT, () => {
  console.log(`Lumina Secure Node running on port ${PORT}`);
});

import { UserProfile, Project, SiteConfig, WithdrawalRequest } from '../types';

const API_BASE_URL = 'http://localhost:5000/api';

class ApiService {
  private static instance: ApiService;
  private isServerMode: boolean = false;

  private constructor() {
    this.checkServerStatus();
  }

  public static getInstance(): ApiService {
    if (!ApiService.instance) {
      ApiService.instance = new ApiService();
    }
    return ApiService.instance;
  }

  private async checkServerStatus() {
    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 1000);
      const res = await fetch(`${API_BASE_URL}/health`, { signal: controller.signal });
      clearTimeout(timeoutId);
      this.isServerMode = res.ok;
    } catch (e) {
      this.isServerMode = false;
      console.warn("Lumina Backend not detected. Switching to Secure Local Protocol.");
    }
  }

  private getAuthHeader() {
    const token = localStorage.getItem('lumina_token');
    return token ? { 'Authorization': `Bearer ${token}` } : {};
  }

  // --- GENERIC REQUEST HANDLER ---
  private async request(endpoint: string, options: RequestInit = {}) {
    if (!this.isServerMode) return this.handleLocalSimulation(endpoint, options);

    const url = `${API_BASE_URL}${endpoint}`;
    const headers = {
      'Content-Type': 'application/json',
      ...this.getAuthHeader(),
      ...(options.headers || {})
    };

    const response = await fetch(url, { ...options, headers });
    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.message || 'Request failed');
    }
    return response.json();
  }

  // --- LOCAL PROTOCOL SIMULATION ---
  private handleLocalSimulation(endpoint: string, options: RequestInit) {
    const method = options.method || 'GET';
    const body = options.body ? JSON.parse(options.body as string) : null;

    if (endpoint === '/auth/login') {
      const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');
      const user = users.find((u: any) => (u.email === body.email || u.mobile === body.email) && u.password === body.password);
      if (!user) throw new Error('Invalid credentials');
      if (user.isBlocked) throw new Error('Account blocked');

      localStorage.setItem('lumina_token', 'local-sim-token-' + Date.now());
      const { password, ...safeUser } = user;
      return { user: safeUser, token: 'mock-jwt' };
    }

    if (endpoint === '/admin/users' && method === 'GET') {
      return JSON.parse(localStorage.getItem('lumina_users') || '[]');
    }

    if (endpoint === '/admin/config' && method === 'POST') {
      localStorage.setItem('lumina_site_config', JSON.stringify(body));
      return { config: body };
    }

    // Fallback for non-simulated endpoints
    return null;
  }

  // --- PUBLIC API ---

  async login(credentials: any) {
    return this.request('/auth/login', {
      method: 'POST',
      body: JSON.stringify(credentials)
    });
  }

  async signup(data: any) {
    return this.request('/auth/signup', {
      method: 'POST',
      body: JSON.stringify(data)
    });
  }

  async getUsers(): Promise<UserProfile[]> {
    return this.request('/admin/users');
  }

  async updateSiteConfig(config: any) {
    return this.request('/admin/config', {
      method: 'POST',
      body: JSON.stringify(config)
    });
  }
}

