const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<StudioMode>(StudioMode.VIDEO);
  const [projects, setProjects] = useState<Project[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [user, setUser] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('lumina_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [siteConfig, setSiteConfig] = useState<SiteConfig>(() => {
    const saved = localStorage.getItem('lumina_site_config');
    return saved ? JSON.parse(saved) : { maintenanceMode: false, activeModules: { video: true, photo: true, paint: true, ads: true, office: true, shop: true }, globalAnnouncement: "" };
  });

  useEffect(() => {
    if (user) {
      localStorage.setItem('lumina_session', JSON.stringify(user));
      const saved = localStorage.getItem(`lumina_projects_${user.email}`);
      setProjects(saved ? JSON.parse(saved) : []);
    }
    const interval = setInterval(() => {
        const saved = localStorage.getItem('lumina_site_config');
        if (saved) setSiteConfig(JSON.parse(saved));
    }, 2000);
    return () => clearInterval(interval);
  }, [user]);

  const saveProject = (project: Project) => {
    if (!user) return;
    const updated = [project, ...projects.filter(p => p.id !== project.id)];
    setProjects(updated);
    localStorage.setItem(`lumina_projects_${user.email}`, JSON.stringify(updated));
  };

  const handleElevate = () => {
    if (!user) return;
    const elevatedUser = { ...user, role: 'Studio Admin' };
    setUser(elevatedUser);
    localStorage.setItem('lumina_session', JSON.stringify(elevatedUser));

    const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const updatedUsers = users.map((u: any) => u.email === user.email ? { ...u, role: 'Studio Admin', isApproved: true } : u);
    localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));
  };

  if (!user) return <Auth onLogin={setUser} />;

  if (siteConfig.maintenanceMode && user.role !== 'Studio Admin') {
    return (
      <div className="h-screen bg-[#020617] flex flex-col items-center justify-center p-10 text-center">
        <div className="p-10 bg-rose-600/10 rounded-full border border-rose-500/20 text-rose-500 mb-10">
          <Construction className="w-24 h-24" />
        </div>
        <h2 className="text-4xl font-black text-white uppercase tracking-tighter mb-4">Under Maintenance</h2>
        <p className="text-slate-500 max-w-lg font-medium leading-relaxed uppercase tracking-widest text-xs">সিস্টেমের গুরুত্বপূর্ণ আপগ্রেড চলছে। খুব শীঘ্রই আমরা ফিরে আসছি। ধৈর্য ধরার জন্য ধন্যবাদ।</p>
        {siteConfig.globalAnnouncement && (
            <div className="mt-10 p-6 bg-slate-900 border border-slate-800 rounded-3xl text-sm text-slate-300 italic">
                "{siteConfig.globalAnnouncement}"
            </div>
        )}
      </div>
    );
  }

  const ModuleGuard = ({ module, children }: { module: string, children?: React.ReactNode }) => {
    const moduleKey = module as keyof SiteConfig['activeModules'];
    if (!siteConfig.activeModules[moduleKey] && user.role !== 'Studio Admin') {
      return (
        <div className="h-full flex flex-col items-center justify-center text-center p-20 space-y-6">
          <div className="p-8 bg-amber-500/10 rounded-full text-amber-500"><Construction className="w-16 h-16" /></div>
          <h3 className="text-2xl font-black text-white uppercase">Module Offline</h3>
          <p className="text-slate-500 text-xs font-black uppercase tracking-widest">এই মডিউলটি সাময়িকভাবে বন্ধ রাখা হয়েছে।</p>
        </div>
      );
    }
    return <>{children}</>;
  };

  return (
    <HashRouter>
      <div className="flex h-screen bg-[#020617] text-slate-100 overflow-hidden font-sans">
        <div className="fixed top-0 inset-x-0 h-8 bg-black/40 backdrop-blur-md flex items-center justify-between px-6 z-[60] border-b border-white/5 select-none pointer-events-none">
           <div className="flex items-center space-x-2">
              <div className="w-2.5 h-2.5 rounded-full bg-rose-500/50" />
              <div className="w-2.5 h-2.5 rounded-full bg-amber-500/50" />
              <div className="w-2.5 h-2.5 rounded-full bg-emerald-500/50" />
           </div>
           <p className="text-[9px] font-black uppercase tracking-[0.4em] text-slate-600">Lumina Desktop Studio x64</p>
           <div className="w-20" />
        </div>

        <Sidebar isOpen={isSidebarOpen} toggle={() => setIsSidebarOpen(!isSidebarOpen)} activeMode={activeMode} setActiveMode={setActiveMode} lang={user.language as any} isAdmin={user.role === 'Studio Admin'} />

        <div className="flex-1 flex flex-col min-w-0 h-full relative pt-8">
          <Header user={user} onLogout={() => setUser(null)} setLanguage={(l) => setUser({...user, language: l})} onElevate={handleElevate} />

          <main className="flex-1 overflow-auto p-4 md:p-10 bg-gradient-to-br from-[#020617] to-[#0f172a]">
            <Routes>
              <Route path="/" element={<Dashboard projects={projects} setActiveMode={setActiveMode} user={user} />} />
              <Route path="/video" element={<ModuleGuard module="video"><VideoEditor onSave={saveProject} /></ModuleGuard>} />
              <Route path="/photo" element={<ModuleGuard module="photo"><PhotoEditor onSave={saveProject} /></ModuleGuard>} />
              <Route path="/paint" element={<ModuleGuard module="paint"><PaintStudio onSave={saveProject} /></ModuleGuard>} />
              <Route path="/ads" element={<ModuleGuard module="ads"><AdBuilder onSave={saveProject} /></ModuleGuard>} />
              <Route path="/audiobook" element={<AudiobookStudio onSave={saveProject} />} />
              <Route path="/education" element={<EducationStudio />} />
              <Route path="/templates" element={<TemplatesGallery />} />
              <Route path="/admin" element={user.role === 'Studio Admin' ? <AdminPanel /> : <Navigate to="/" />} />
              <Route path="/profile" element={<UserProfilePage user={user} setUser={setUser} onLogout={() => setUser(null)} />} />
              <Route path="/storage" element={<CloudStorage projects={projects} />} />
              <Route path="/shop" element={<ModuleGuard module="shop"><Shop user={user} /></ModuleGuard>} />
              <Route path="/communication" element={<CommunicationStudio user={user} />} />
              <Route path="/office" element={<ModuleGuard module="office"><OfficeSuite user={user} onSave={saveProject} /></ModuleGuard>} />
              <Route path="/support" element={<SupportCenter user={user} />} />
            </Routes>
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ShieldAlert, Users, Activity, Search, CheckCircle, RefreshCw, ShieldCheck,
  Trash2, DollarSign, History, CreditCard, UserCheck, UserMinus, Coins,
