  FileText, Settings, Globe, Server, Terminal, Copy, ChevronDown, Cpu,
  Database, Lock, Zap, Plus, ShieldX, AlertTriangle, Clock, Check, X,
  Filter, Eye, UserCog, Fingerprint, Shield, BarChart3, Radio, Power,
  Construction, CloudCog, Key, Unlock, ShieldQuestion, Binary
} from 'lucide-react';
import { SubscriptionTier, UserProfile, StudioMode, WithdrawalRequest, SiteConfig } from '../types';
import { api } from '../services/apiService';

type AdminTab = 'nodes' | 'ledger' | 'security' | 'system';

const AdminPanel: React.FC = () => {
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [unlockPin, setUnlockPin] = useState("");
  const [isDecrypting, setIsDecrypting] = useState(false);
  const [activeTab, setActiveTab] = useState<AdminTab>('nodes');
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const [users, setUsers] = useState<UserProfile[]>([]);
  const [withdrawals, setWithdrawals] = useState<WithdrawalRequest[]>([]);
  const [siteConfig, setSiteConfig] = useState<SiteConfig>({
    maintenanceMode: false,
    activeModules: { video: true, photo: true, paint: true, ads: true, office: true, shop: true },
    globalAnnouncement: "",
    hardenedMode: false
  });

  const [systemStats, setSystemStats] = useState({ cpu: 42, memory: 68, storage: 84, traffic: 1204, threats: 0 });

  const loadData = async () => {
    setIsRefreshing(true);
    try {
      const fetchedUsers = await api.getUsers();
      setUsers(fetchedUsers);
      // Payouts and other stats would follow
    } catch (e) {
      console.error("Admin data fetch failed", e);
    } finally {
      setIsRefreshing(false);
    }
  };

  useEffect(() => {
    if (isUnlocked) loadData();
    const interval = setInterval(() => {
      setSystemStats(prev => ({
        ...prev,
        cpu: Math.floor(Math.random() * 20) + 30,
        traffic: prev.traffic + Math.floor(Math.random() * 5),
        threats: Math.random() > 0.95 ? prev.threats + 1 : prev.threats
      }));
    }, 3000);
    return () => clearInterval(interval);
  }, [isUnlocked]);

  const handleUnlock = () => {
    setIsDecrypting(true);
    setTimeout(() => {
      if (unlockPin === 'admin123' || unlockPin === '0000') {
        setIsUnlocked(true);
      }
      setIsDecrypting(false);
    }, 1200);
  };

  const handleUpdateConfig = async (newConfig: Partial<SiteConfig>) => {
    const updated = { ...siteConfig, ...newConfig };
    setSiteConfig(updated);
    await api.updateSiteConfig(updated);
  };

  if (!isUnlocked) {
    return (
      <div className="h-[80vh] flex flex-col items-center justify-center p-6 animate-in fade-in duration-1000">
        <div className="w-full max-w-md bg-slate-900 border border-slate-800 rounded-[3.5rem] p-12 shadow-2xl relative overflow-hidden text-center space-y-8">
           <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-rose-500 to-transparent animate-pulse" />
           <div className="w-24 h-24 bg-rose-500/10 rounded-[2rem] border border-rose-500/20 flex items-center justify-center text-rose-500 mx-auto shadow-2xl">
              <Lock className="w-10 h-10" />
           </div>
           <div className="space-y-2">
              <h2 className="text-3xl font-black text-white uppercase tracking-tighter">Root Vault</h2>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Authorized Personnel Only</p>
           </div>
           <div className="space-y-4">
              <input 
                type="password"
                value={unlockPin}
                onChange={(e) => setUnlockPin(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleUnlock()}
                placeholder="Enter root pin"
                className="w-full bg-slate-950 border border-slate-800 rounded-[1.5rem] py-5 text-center font-black tracking-[0.5em] text-white outline-none"
              />
              <button 
                onClick={handleUnlock}
                disabled={isDecrypting || !unlockPin}
                className="w-full py-5 bg-rose-600 hover:bg-rose-500 text-white rounded-[1.5rem] text-[10px] font-black uppercase tracking-[0.3em] transition-all disabled:opacity-30"
              >
                {isDecrypting ? <RefreshCw className="w-5 h-5 animate-spin mx-auto" /> : "Decrypt Vault"}
              </button>
           </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto space-y-10 animate-in fade-in duration-700 pb-20">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-8">
        <div className="flex items-center space-x-8">
           <div className="w-20 h-20 bg-emerald-600/10 rounded-[2.5rem] border border-emerald-500/30 flex items-center justify-center text-emerald-500 shadow-2xl relative">
              <ShieldCheck className="w-10 h-10" />
              <div className="absolute -top-1 -right-1 w-4 h-4 bg-emerald-500 rounded-full border-2 border-slate-950" />
           </div>
           <div>
              <h2 className="text-5xl font-black tracking-tighter uppercase text-white leading-none">Root <span className="text-emerald-500">Access</span></h2>
              <p className="text-[9px] font-black text-slate-500 uppercase mt-3 tracking-widest">Connected to Secure Backend Cluster v4.0</p>
           </div>
        </div>

        <div className="flex bg-slate-900 border border-slate-800 p-2 rounded-[2.5rem] shadow-2xl">
          {[
            { id: 'nodes', label: 'Nodes', icon: Users },
            { id: 'ledger', label: 'Ledger', icon: DollarSign },
            { id: 'security', label: 'Security', icon: Shield },
            { id: 'system', label: 'System', icon: CloudCog }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`px-8 py-3.5 rounded-[1.8rem] text-[10px] font-black uppercase tracking-widest transition-all flex items-center ${
                activeTab === tab.id ? 'bg-emerald-600 text-white' : 'text-slate-500 hover:text-white'
              }`}
            >
              <tab.icon className="w-4 h-4 mr-3" /> {tab.label}
            </button>
          ))}
          <button onClick={() => setIsUnlocked(false)} className="px-6 py-3.5 rounded-[1.8rem] text-rose-500 hover:bg-rose-500 hover:text-white transition-all ml-2">
            <Power className="w-4 h-4" />
          </button>
        </div>
      </div>

      <div className="bg-slate-900/40 border border-slate-800 rounded-[4rem] overflow-hidden shadow-2xl min-h-[600px] flex flex-col">
        <div className="p-10 border-b border-slate-800 bg-black/40 backdrop-blur-xl flex flex-col md:flex-row items-center justify-between gap-10">
           <h3 className="text-2xl font-black uppercase tracking-tight flex items-center text-white">
