              </div>
           </div>
        </div>

        <div className="flex-1 overflow-auto p-10">
           {activeTab === 'nodes' && (
             <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 overflow-hidden border border-slate-800 rounded-3xl">
                <table className="w-full text-left">
                   <thead>
                      <tr className="bg-slate-950/60 text-[10px] uppercase font-black text-slate-600 tracking-[0.3em] border-b border-slate-800">
                         <th className="px-8 py-6">Node Identity</th>
                         <th className="px-8 py-6">Authorization</th>
                         <th className="px-8 py-6">Plan</th>
                         <th className="px-8 py-6 text-right">Actions</th>
                      </tr>
                   </thead>
                   <tbody className="divide-y divide-slate-800/40">
                      {users.map(u => (
                        <tr key={u.email} className="group hover:bg-white/[0.02] transition-all">
                           <td className="px-8 py-6">
                              <div className="flex items-center space-x-4">
                                 <img src={u.avatar} className="w-10 h-10 rounded-xl bg-slate-800" alt="" />
                                 <div>
                                    <p className="text-sm font-black text-white">{u.name}</p>
                                    <p className="text-[10px] text-slate-500">{u.email}</p>
                                 </div>
                              </div>
                           </td>
                           <td className="px-8 py-6">
                              <span className={`text-[8px] font-black uppercase px-3 py-1 rounded-lg ${u.isBlocked ? 'bg-rose-500/10 text-rose-500' : 'bg-emerald-500/10 text-emerald-500'}`}>
