           )}

           {activeTab === 'system' && (
             <div className="grid grid-cols-1 md:grid-cols-4 gap-8">
                {[
                  { label: 'CPU LOAD', val: `${systemStats.cpu}%`, icon: Cpu, color: 'text-emerald-500' },
