import React, { useState } from 'react';
import { Search, Bell, Globe, ChevronDown, Terminal, ShieldAlert, X } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { UserProfile } from '../types';
import { translations } from '../App';

interface HeaderProps {
  user: UserProfile;
  onLogout: () => void;
  setLanguage: (lang: any) => void;
  onElevate: () => void;
}

const Header: React.FC<HeaderProps> = ({ user, setLanguage, onElevate }) => {
  const navigate = useNavigate();
  const [showLangMenu, setShowLangMenu] = useState(false);
  const [searchVal, setSearchVal] = useState("");
  const [isElevating, setIsElevating] = useState(false);

  const handleSearch = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      const query = searchVal.trim().toUpperCase();
      if (query === 'LUMINA-SYS-ROOT') {
        setIsElevating(true);
        setSearchVal("");
        setTimeout(() => {
          onElevate();
          setIsElevating(false);
          navigate('/admin');
        }, 1200);
      }
    }
  };

  const languages = [
    { code: 'en', label: 'English', flag: '🇺🇸' },
    { code: 'bn', label: 'বাংলা', flag: '🇧🇩' },
    { code: 'hi', label: 'हिन्दी', flag: '🇮🇳' },
    { code: 'es', label: 'Español', flag: '🇪🇸' },
    { code: 'ar', label: 'العربية', flag: '🇸🇦' },
    { code: 'fr', label: 'Français', flag: '🇫🇷' }
  ];

  const isCommand = searchVal.toUpperCase().startsWith('LUMINA');

  return (
    <header className="h-20 border-b border-slate-800 bg-slate-950/80 backdrop-blur-2xl flex items-center justify-between px-8 sticky top-0 z-40">
      {isElevating && <div className="fixed inset-0 bg-rose-600/20 animate-pulse z-[200] pointer-events-none" />}

      <div className="flex-1 max-w-2xl relative">
        <div className={`absolute left-6 top-1/2 -translate-y-1/2 transition-all ${isCommand ? 'text-rose-500 animate-pulse' : 'text-slate-500'}`}>
          {isCommand ? <Terminal className="w-5 h-5" /> : <Search className="w-4 h-4" />}
        </div>
        <input 
          type="text" 
          value={searchVal}
          onChange={(e) => setSearchVal(e.target.value)}
          onKeyDown={handleSearch}
          placeholder={isElevating ? "AUTHORIZING ROOT IDENTITY..." : "Search projects or enter master command..."} 
          className={`w-full bg-slate-900 border rounded-2xl py-4 pl-16 pr-12 text-xs font-bold uppercase transition-all duration-500 ${
            isCommand ? 'border-rose-500 text-rose-500 shadow-[0_0_20px_rgba(225,29,72,0.15)]' : 'border-slate-800 focus:border-indigo-500/50'
          }`}
        />
        {searchVal && <X className="absolute right-5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-700 cursor-pointer" onClick={() => setSearchVal("")} />}
      </div>

      <div className="flex items-center space-x-6 ml-8">
        <div className="relative">
          <button onClick={() => setShowLangMenu(!showLangMenu)} className="flex items-center space-x-3 px-5 py-2.5 bg-slate-900 border border-slate-800 rounded-xl text-[10px] font-black uppercase text-slate-500">
            <Globe className="w-4 h-4" />
            <span>{languages.find(l => l.code === user.language)?.label || 'English'}</span>
          </button>
          {showLangMenu && (
            <div className="absolute top-full right-0 mt-4 w-48 bg-slate-900 border border-slate-800 rounded-3xl shadow-2xl p-3 z-50">
              {languages.map(lang => (
                <button key={lang.code} onClick={() => { setLanguage(lang.code); setShowLangMenu(false); }} className={`w-full flex items-center space-x-4 p-4 rounded-xl text-[10px] font-black uppercase ${user.language === lang.code ? 'bg-indigo-600 text-white' : 'hover:bg-slate-800 text-slate-500'}`}>
                  <span>{lang.flag}</span> <span>{lang.label}</span>
                </button>
              ))}
            </div>
          )}
        </div>
        <div onClick={() => navigate('/profile')} className="flex items-center space-x-4 cursor-pointer group">
           <img src={user.avatar} className="w-11 h-11 rounded-xl border-2 border-indigo-600 group-hover:scale-110 transition-all" alt="Profile" />
        </div>
      </div>
    </header>
  );
};

export default Header;

