type Tool = 'brush' | 'eraser' | 'shape';
type RenderStyle = '3d-disney' | '2d-anime' | '3d-realistic' | 'comic' | 'stylized-vfx';

const PaintStudio: React.FC<PaintStudioProps> = ({ onSave }) => {
  const location = useLocation();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<Tool>('brush');
  const [color, setColor] = useState('#6366f1');
  const [strokeWidth, setStrokeWidth] = useState(8);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [renderStyle, setRenderStyle] = useState<RenderStyle>('3d-disney');

  const lastPos = useRef<{ x: number, y: number } | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#020617';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
      }
    }
  }, []);

  const getMousePos = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.MouseEvent) => {
    setIsDrawing(true);
    lastPos.current = getMousePos(e);
  };

  const draw = (e: React.MouseEvent) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    const currentPos = getMousePos(e);
    ctx.beginPath();
    ctx.moveTo(lastPos.current!.x, lastPos.current!.y);
    ctx.lineTo(currentPos.x, currentPos.y);
    ctx.strokeStyle = tool === 'eraser' ? '#020617' : color;
    ctx.lineWidth = strokeWidth;
    ctx.stroke();
    lastPos.current = currentPos;
  };

  const stopDrawing = () => setIsDrawing(false);

  const handleSynthesizeCharacter = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();

    let styleInstruction = "";
    switch(renderStyle) {
      case '3d-disney': styleInstruction = "3D Pixar Disney style character, cinematic lighting, 8k render, professional character design sheet."; break;
      case '2d-anime': styleInstruction = "Studio Ghibli style high-quality anime character, detailed linework."; break;
      case '3d-realistic': styleInstruction = "Unreal Engine 5 hyper-realistic character, MetaHuman standard, 8k octane render."; break;
      case 'comic': styleInstruction = "Modern graphic novel style, high contrast, dynamic character posing."; break;
      case 'stylized-vfx': styleInstruction = "Stylized character with glow effects and magical particles, stylized low-poly but detailed textures."; break;
    }

    const finalPrompt = `Professional creative character asset based on user sketch: ${prompt}. ${styleInstruction}`;
    const result = await gemini.generateImage(finalPrompt, "1:1", true);

    if (result) {
      const img = new Image();
      img.onload = () => {
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx) {
          ctx.drawImage(img, 0, 0, canvasRef.current!.width, canvasRef.current!.height);
        }
      };
      img.src = result;
    }
    setIsGenerating(false);
  };

  return (
    <div className="h-[calc(100vh-120px)] flex flex-col gap-6 animate-in fade-in duration-500 overflow-hidden">
      <div className="flex justify-between items-center bg-slate-900/80 backdrop-blur-xl p-4 rounded-3xl border border-white/5 shadow-2xl">
        <div className="flex items-center space-x-6">
           <div className="p-2.5 bg-indigo-600 rounded-xl">
              <UserPlus className="w-5 h-5 text-white" />
           </div>
           <h2 className="text-xl font-black uppercase tracking-tight">Animation Character Studio</h2>
        </div>
        <div className="flex items-center space-x-4">
          <button onClick={() => {
            const ctx = canvasRef.current?.getContext('2d');
            if (ctx) { ctx.fillStyle = '#020617'; ctx.fillRect(0,0,1600,1200); }
          }} className="px-5 py-2.5 bg-slate-800 text-slate-400 rounded-xl text-[10px] font-black uppercase tracking-widest border border-slate-700">Clear</button>
          <button onClick={handleSynthesizeCharacter} disabled={isGenerating || !prompt} className="px-8 py-2.5 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center">
            <Sparkles className="w-4 h-4 mr-2" /> Synthesize Character
          </button>
        </div>
      </div>

      <div className="flex-1 flex gap-6 min-h-0">
         {/* Toolbar */}
         <div className="w-20 bg-slate-900/80 backdrop-blur-xl rounded-[2.5rem] border border-white/5 p-4 flex flex-col items-center gap-6 shadow-2xl">
            {[
              { id: 'brush', icon: Pencil },
              { id: 'eraser', icon: Eraser },
              { id: 'shape', icon: Shapes },
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setTool(t.id as Tool)} 
                className={`p-4 rounded-2xl transition-all ${tool === t.id ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-500 hover:text-white'}`}
              >
                <t.icon className="w-6 h-6" />
              </button>
            ))}
            <div className="w-10 h-px bg-white/5 my-2" />
            {['#6366f1', '#10b981', '#f43f5e', '#ffffff'].map(c => (
              <button key={c} onClick={() => setColor(c)} className={`w-10 h-10 rounded-2xl border-2 transition-all ${color === c ? 'border-white scale-110 shadow-lg' : 'border-transparent opacity-60'}`} style={{ backgroundColor: c }} />
            ))}
         </div>

         {/* Canvas Area */}
         <div className="flex-1 bg-black rounded-[3.5rem] border border-white/5 p-8 flex flex-col shadow-2xl relative overflow-hidden group">
            <div className="flex-1 bg-slate-950 rounded-[2.5rem] overflow-hidden relative cursor-crosshair">
               <canvas 
                ref={canvasRef} width={1600} height={1200}
                onMouseDown={startDrawing} onMouseMove={draw} onMouseUp={stopDrawing} onMouseLeave={stopDrawing}
                className="w-full h-full object-contain"
               />
               {isGenerating && (
                 <div className="absolute inset-0 bg-black/60 backdrop-blur-xl flex flex-col items-center justify-center z-50">
                    <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-6" />
                    <p className="text-indigo-400 font-black uppercase tracking-[0.5em] text-xs animate-pulse">Generating 3D Neural Blueprint...</p>
                 </div>
               )}
            </div>

            {/* Prompt Control */}
            <div className="mt-8 flex gap-4">
              <input 
                value={prompt} onChange={(e) => setPrompt(e.target.value)}
                placeholder="Describe character identity: 'Alien queen with neon tentacles'..." 
                className="flex-1 bg-slate-900 border border-slate-800 rounded-3xl px-8 py-4 text-white font-medium focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none"
              />
              <div className="flex bg-slate-900 border border-slate-800 p-1 rounded-2xl">
                {[
                  { id: '3d-disney', label: 'Disney' },
                  { id: '2d-anime', label: 'Anime' },
                  { id: '3d-realistic', label: 'Real' }
                ].map(s => (
                  <button 
                    key={s.id} 
                    onClick={() => setRenderStyle(s.id as RenderStyle)}
                    className={`px-5 py-2.5 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${renderStyle === s.id ? 'bg-indigo-600 text-white' : 'text-slate-500'}`}
                  >
                    {s.label}
                  </button>
                ))}
              </div>
            </div>
         </div>

         {/* Inspect / Asset Panel */}
         <div className="w-72 bg-slate-900/50 backdrop-blur-xl rounded-[2.5rem] border border-white/5 p-8 flex flex-col gap-8 shadow-2xl">
            <h3 className="text-[11px] font-black text-slate-500 uppercase tracking-widest flex items-center"><Users className="w-4 h-4 mr-3" /> Asset Library</h3>
            <div className="flex-1 space-y-4 overflow-y-auto custom-scrollbar">
               {[
                 { id: 1, label: 'Standard Skeleton', icon: Ghost },
                 { id: 2, label: 'Facial Rigging', icon: Eye },
                 { id: 3, label: 'Posing Pins', icon: Move3d },
               ].map(m => (
                 <div key={m.id} className="p-4 bg-black/40 border border-white/5 rounded-2xl flex items-center justify-between group hover:border-indigo-500/30 transition-all cursor-pointer">
                    <div className="flex items-center space-x-3">
