    } finally {
      setIsRefreshing(false);
    }
  };

  useEffect(() => {
    if (isUnlocked) loadData();
    const interval = setInterval(() => {
      setSystemStats(prev => ({
        ...prev,
        cpu: Math.floor(Math.random() * 20) + 30,
