const express = require('express');
const cors = require('cors');
const jwt = require('jsonwebtoken');
const bcrypt = require('bcryptjs');
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 5000;
const SECRET_KEY = process.env.JWT_SECRET || 'lumina-super-secret-key-2025';

app.use(cors());
app.use(express.json());

// In-memory "Database"
let users = [];
let otpStore = {}; // Stores OTPs mapped to emails
let siteConfig = {
  maintenanceMode: false,
  activeModules: { video: true, photo: true, paint: true, ads: true, office: true, shop: true },
  globalAnnouncement: ""
};

// Default Admin Credentials
const admin = {
  email: "admin@lumina.com",
  password: bcrypt.hashSync("StrongAdmin123", 10),
  role: "Studio Admin"
};

// --- MIDDLEWARE ---

const verifyToken = (req, res, next) => {
  const auth = req.headers.authorization;
  if (!auth) return res.status(401).json({ message: "No token" });

  const token = auth.split(" ")[1];
  try {
    const verified = jwt.verify(token, SECRET_KEY);
    req.user = verified;
    next();
  } catch (err) {
    res.status(401).json({ message: "Invalid token" });
  }
};

const isAdmin = (req, res, next) => {
  if (req.user && (req.user.role === 'Studio Admin' || req.user.role === 'admin')) {
    next();
  } else {
    res.status(403).json({ message: 'Require Admin Role!' });
  }
};

// --- ROUTES ---

// Admin Login with OTP Trigger
app.post("/api/admin/login", async (req, res) => {
  const { email, password } = req.body;

  if (email !== admin.email) {
    return res.status(400).json({ message: "Invalid email" });
  }

  const valid = await bcrypt.compare(password, admin.password);
  if (!valid) {
    return res.status(400).json({ message: "Wrong password" });
  }

  const otp = Math.floor(100000 + Math.random() * 900000);
  otpStore[email] = otp;

  console.log("OTP:", otp); // later send via email
  res.json({ message: "OTP sent" });
});

// Verify Admin OTP and issue Token
app.post("/api/admin/verify-otp", (req, res) => {
  const { email, otp } = req.body;

  if (otpStore[email] != otp) {
    return res.status(400).json({ message: "Invalid OTP" });
  }

  const token = jwt.sign(
    { email, role: "admin" },
    SECRET_KEY,
    { expiresIn: "1h" }
  );

  delete otpStore[email];

  res.json({ 
    token, 
    user: { 
      name: "System Admin", 
      role: "Studio Admin", 
      email,
      avatar: 'https://api.dicebear.com/7.x/identicon/svg?seed=admin' 
    } 
  });
});

// Admin Dashboard Check
app.get("/api/admin/dashboard", verifyToken, (req, res) => {
  res.json({ message: "Welcome Admin" });
});

// User Auth: Login
app.post('/api/auth/login', async (req, res) => {
  const { email, password } = req.body;
  const user = users.find(u => u.email === email || u.mobile === email);

  if (!user) return res.status(404).json({ message: 'Identity node not found.' });
  if (user.isBlocked) return res.status(403).json({ message: 'Access protocol suspended.' });

  const passwordIsValid = await bcrypt.compare(password, user.password);
  if (!passwordIsValid) return res.status(401).json({ message: 'Verification failed.' });

  const token = jwt.sign({ id: user.id, role: user.role }, SECRET_KEY, { expiresIn: '24h' });
  const { password: _, ...userProfile } = user;
  res.status(200).json({ token, user: userProfile });
});

// Admin Control: Get Users
app.get('/api/admin/users', [verifyToken, isAdmin], (req, res) => {
  res.json(users.map(({ password, ...rest }) => rest));
});

app.listen(PORT, () => {
  console.log(`Lumina Secure Desktop Backend active on port ${PORT}`);
});

