const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<StudioMode>(StudioMode.VIDEO);
  const [projects, setProjects] = useState<Project[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [user, setUser] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('lumina_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [siteConfig, setSiteConfig] = useState<SiteConfig>(() => {
    const saved = localStorage.getItem('lumina_site_config');
    return saved ? JSON.parse(saved) : { maintenanceMode: false, activeModules: { video: true, photo: true, paint: true, ads: true, office: true, shop: true }, globalAnnouncement: "" };
  });

  useEffect(() => {
    if (user) {
      localStorage.setItem('lumina_session', JSON.stringify(user));
      const saved = localStorage.getItem(`lumina_projects_${user.email}`);
      setProjects(saved ? JSON.parse(saved) : []);
    }
  }, [user]);

  const saveProject = (project: Project) => {
    if (!user) return;
    const updated = [project, ...projects.filter(p => p.id !== project.id)];
    setProjects(updated);
    localStorage.setItem(`lumina_projects_${user.email}`, JSON.stringify(updated));
  };

  const handleElevate = () => {
    if (!user) return;
    const elevatedUser = { ...user, role: 'admin' };
    setUser(elevatedUser);
    localStorage.setItem('lumina_session', JSON.stringify(elevatedUser));
  };

  if (!user) return <Auth onLogin={setUser} />;

  const isRtl = ['ar'].includes(user.language);

  return (
    <HashRouter>
      <div className={`flex h-screen bg-[#020617] text-slate-100 overflow-hidden font-sans ${isRtl ? 'rtl' : 'ltr'}`}>
        {/* Desktop Header Frame - Modern Window Controls */}
        <div className="fixed top-0 inset-x-0 h-10 bg-black/40 backdrop-blur-md flex items-center justify-between px-6 z-[100] border-b border-white/5 select-none">
           <div className="flex items-center space-x-2.5">
              <div className="w-3 h-3 rounded-full bg-rose-500/80 shadow-[0_0_10px_rgba(244,63,94,0.3)]" />
              <div className="w-3 h-3 rounded-full bg-amber-500/80 shadow-[0_0_10px_rgba(245,158,11,0.3)]" />
              <div className="w-3 h-3 rounded-full bg-emerald-500/80 shadow-[0_0_10px_rgba(16,185,129,0.3)]" />
           </div>
           <p className="text-[10px] font-black uppercase tracking-[0.6em] text-slate-500 pl-16">Lumina Enterprise Creative Studio x64</p>
           <div className="flex items-center space-x-6">
              <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">Build 4.5.0-Stable</span>
              <div className="w-20" />
           </div>
        </div>

        <Sidebar isOpen={isSidebarOpen} toggle={() => setIsSidebarOpen(!isSidebarOpen)} activeMode={activeMode} setActiveMode={setActiveMode} lang={user.language as any} isAdmin={user.role === 'admin'} />

        <div className="flex-1 flex flex-col min-w-0 h-full relative pt-10">
          <Header user={user} onLogout={() => setUser(null)} setLanguage={(l) => setUser({...user, language: l})} onElevate={handleElevate} />

          <main className="flex-1 overflow-hidden relative bg-gradient-to-br from-[#020617] to-[#0f172a]">
            <div className="absolute inset-0 overflow-auto p-4 md:p-10 custom-scrollbar">
                <Routes>
                <Route path="/" element={<Dashboard projects={projects} setActiveMode={setActiveMode} user={user} />} />
                <Route path="/video" element={<VideoEditor onSave={saveProject} />} />
                <Route path="/photo" element={<PhotoEditor onSave={saveProject} />} />
                <Route path="/paint" element={<PaintStudio onSave={saveProject} />} />
                <Route path="/ads" element={<AdBuilder onSave={saveProject} />} />
                <Route path="/audiobook" element={<AudiobookStudio onSave={saveProject} />} />
                <Route path="/education" element={<EducationStudio />} />
                <Route path="/templates" element={<TemplatesGallery />} />
                <Route path="/admin" element={user.role === 'admin' ? <AdminPanel /> : <Navigate to="/" />} />
                <Route path="/profile" element={<UserProfilePage user={user} setUser={setUser} onLogout={() => setUser(null)} />} />
                <Route path="/storage" element={<CloudStorage projects={projects} />} />
                <Route path="/shop" element={<Shop user={user} />} />
                <Route path="/communication" element={<CommunicationStudio user={user} />} />
                <Route path="/office" element={<OfficeSuite user={user} onSave={saveProject} />} />
                <Route path="/support" element={<SupportCenter user={user} />} />
                </Routes>
            </div>
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

