import React, { useState, useRef, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import { 
  Paintbrush, Eraser, Square, Circle, Minus, Wand2, Save, Undo,
  Download, Sparkles, CheckCircle, Box, Layers, Palette, 
  Trash2, RotateCcw, Monitor, MousePointer2, Pencil, Shapes,
  Users, UserPlus, BoxSelect, Move3d, Zap, Ghost, Eye, Maximize2,
  // Fix: Added missing RefreshCw icon import
  RefreshCw
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode } from '../types';

interface PaintStudioProps {
  onSave: (project: Project) => void;
}

type Tool = 'brush' | 'eraser' | 'shape';
type RenderStyle = '3d-disney' | '2d-anime' | '3d-realistic' | 'comic' | 'stylized-vfx' | 'pixel-art' | 'game-asset';

const PaintStudio: React.FC<PaintStudioProps> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<Tool>('brush');
  const [color, setColor] = useState('#6366f1');
  const [strokeWidth, setStrokeWidth] = useState(10);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [renderStyle, setRenderStyle] = useState<RenderStyle>('3d-disney');

  const lastPos = useRef<{ x: number, y: number } | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#020617';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
      }
    }
  }, []);

  const getMousePos = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.MouseEvent) => {
    setIsDrawing(true);
    lastPos.current = getMousePos(e);
  };

  const draw = (e: React.MouseEvent) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    const currentPos = getMousePos(e);
    ctx.beginPath();
    ctx.moveTo(lastPos.current!.x, lastPos.current!.y);
    ctx.lineTo(currentPos.x, currentPos.y);
    ctx.strokeStyle = tool === 'eraser' ? '#020617' : color;
    ctx.lineWidth = strokeWidth;
    ctx.stroke();
    lastPos.current = currentPos;
  };

  const stopDrawing = () => setIsDrawing(false);

  const handleSynthesizeCharacter = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();

    let styleInstruction = "";
    switch(renderStyle) {
      case '3d-disney': styleInstruction = "3D Pixar Disney style character, cinematic lighting, 8k professional render."; break;
      case '2d-anime': styleInstruction = "Modern high-quality anime character, detailed cel-shading, Ghibli style vibes."; break;
      case '3d-realistic': styleInstruction = "Unreal Engine 5 hyper-realistic character, MetaHuman quality, 8k octane render."; break;
      case 'comic': styleInstruction = "Graphic novel art, vibrant inks, dynamic character posing, professional comic style."; break;
      case 'stylized-vfx': styleInstruction = "Stylized character with magical VFX glowing elements and particle systems."; break;
      case 'game-asset': styleInstruction = "Character game asset sheet, front and side views, stylized low-poly but highly detailed textures."; break;
      default: styleInstruction = "Artistic character design.";
    }

    const finalPrompt = `Professional creative character asset based on user sketch: ${prompt}. ${styleInstruction}`;
    const result = await gemini.generateImage(finalPrompt, "1:1", true);

    if (result) {
      const img = new Image();
      img.onload = () => {
        const ctx = canvasRef.current?.getContext('2d');
        if (ctx) {
          ctx.drawImage(img, 0, 0, canvasRef.current!.width, canvasRef.current!.height);
        }
        onSave({ 
          id: Date.now().toString(), 
          name: prompt.substring(0, 20) || 'Character Synth', 
          type: StudioMode.PAINT, 
          thumbnail: result, 
          updatedAt: Date.now(), 
          status: 'draft', 
          data: { prompt, renderStyle } 
        });
      };
      img.src = result;
    }
    setIsGenerating(false);
  };

  return (
    <div className="h-[calc(100vh-120px)] flex flex-col gap-6 animate-in fade-in duration-700 overflow-hidden">
      {/* Studio Header */}
      <div className="flex justify-between items-center bg-slate-900/80 backdrop-blur-xl p-5 rounded-[2.5rem] border border-white/5 shadow-2xl">
        <div className="flex items-center space-x-6">
           <div className="p-3 bg-indigo-600 rounded-2xl shadow-xl shadow-indigo-600/20">
              <UserPlus className="w-6 h-6 text-white" />
           </div>
           <div>
              <h2 className="text-2xl font-black uppercase tracking-tight">Character <span className="text-indigo-500">Creation</span> Studio</h2>
              <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest mt-1">Neural Asset Synthesis Engine v4.0</p>
           </div>
        </div>
        <div className="flex items-center space-x-4">
          <button onClick={() => {
            const ctx = canvasRef.current?.getContext('2d');
            if (ctx) { ctx.fillStyle = '#020617'; ctx.fillRect(0,0,1600,1200); }
          }} className="px-6 py-3 bg-slate-800 text-slate-400 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-slate-700 hover:text-white transition-all">Clear Canvas</button>
          <button onClick={handleSynthesizeCharacter} disabled={isGenerating || !prompt} className="px-10 py-3 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center hover:bg-indigo-500 transition-all disabled:opacity-50">
            {isGenerating ? <RefreshCw className="w-4 h-4 mr-2 animate-spin" /> : <Sparkles className="w-4 h-4 mr-2" />}
            Synthesize Character
          </button>
        </div>
      </div>

      <div className="flex-1 flex gap-6 min-h-0">
         {/* Paint Toolbar */}
         <div className="w-24 bg-slate-900/80 backdrop-blur-xl rounded-[3rem] border border-white/5 p-5 flex flex-col items-center gap-6 shadow-2xl">
            {[
              { id: 'brush', icon: Pencil, label: 'Pencil' },
              { id: 'eraser', icon: Eraser, label: 'Eraser' },
              { id: 'shape', icon: Shapes, label: 'Shapes' },
            ].map(t => (
              <button 
                key={t.id} 
                onClick={() => setTool(t.id as Tool)} 
                title={t.label}
                className={`p-5 rounded-[1.8rem] transition-all group relative ${tool === t.id ? 'bg-indigo-600 text-white shadow-2xl' : 'text-slate-500 hover:text-white hover:bg-white/5'}`}
              >
                <t.icon className="w-6 h-6" />
                {tool === t.id && <div className="absolute -right-2 top-1/2 -translate-y-1/2 w-1.5 h-1.5 bg-white rounded-full" />}
              </button>
            ))}
            <div className="w-12 h-px bg-white/5 my-2" />
            <input 
              type="color" 
              value={color} 
              onChange={(e) => setColor(e.target.value)} 
              className="w-12 h-12 rounded-2xl border-none cursor-pointer p-0 bg-transparent overflow-hidden shadow-xl" 
            />
            <div className="w-12 h-px bg-white/5 my-2" />
            <div className="flex flex-col gap-3">
               {['#6366f1', '#10b981', '#f43f5e', '#ffffff'].map(c => (
                 <button key={c} onClick={() => setColor(c)} className={`w-10 h-10 rounded-full border-2 transition-all ${color === c ? 'border-white scale-110 shadow-lg' : 'border-transparent opacity-60'}`} style={{ backgroundColor: c }} />
               ))}
            </div>
         </div>

         {/* Canvas Desktop Area */}
         <div className="flex-1 bg-black rounded-[4rem] border border-white/5 p-10 flex flex-col shadow-2xl relative overflow-hidden group">
            <div className="flex-1 bg-[#020617] rounded-[3rem] overflow-hidden relative cursor-crosshair border border-white/5 shadow-inner group">
               <canvas 
                ref={canvasRef} width={1600} height={1200}
                onMouseDown={startDrawing} onMouseMove={draw} onMouseUp={stopDrawing} onMouseLeave={stopDrawing}
                className="w-full h-full object-contain"
               />
               <div className="absolute top-8 right-8 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button className="p-4 bg-black/60 backdrop-blur-md rounded-2xl text-white border border-white/10"><Maximize2 className="w-5 h-5" /></button>
               </div>
               {isGenerating && (
                 <div className="absolute inset-0 bg-black/70 backdrop-blur-2xl flex flex-col items-center justify-center z-50 animate-in fade-in duration-500">
                    <div className="w-20 h-20 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-8 shadow-[0_0_50px_rgba(99,102,241,0.5)]" />
                    <p className="text-indigo-400 font-black uppercase tracking-[0.5em] text-sm animate-pulse text-center">Constructing Neural Mesh...</p>
                 </div>
               )}
            </div>

            {/* AI Control Center */}
            <div className="mt-10 flex gap-6">
              <div className="flex-1 relative">
                <input 
                  value={prompt} onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Describe Identity: 'Cybernetic warrior with obsidian armor'..." 
                  className="w-full bg-slate-900 border border-slate-800 rounded-[2.5rem] px-10 py-6 text-white font-medium focus:ring-8 focus:ring-indigo-500/10 transition-all outline-none shadow-2xl placeholder:text-slate-700"
                />
                <Sparkles className="absolute right-8 top-1/2 -translate-y-1/2 w-6 h-6 text-indigo-500/30" />
              </div>
              <div className="flex bg-slate-900 border border-slate-800 p-2 rounded-[2.5rem] shadow-2xl">
                {[
                  { id: '3d-disney', label: 'Disney' },
                  { id: '2d-anime', label: 'Anime' },
                  { id: '3d-realistic', label: 'Realistic' },
                  { id: 'game-asset', label: 'Game' }
                ].map(s => (
                  <button 
                    key={s.id} 
                    onClick={() => setRenderStyle(s.id as RenderStyle)}
                    className={`px-8 py-4 rounded-[1.8rem] text-[10px] font-black uppercase tracking-widest transition-all ${renderStyle === s.id ? 'bg-indigo-600 text-white shadow-2xl scale-105' : 'text-slate-500 hover:text-white'}`}
                  >
                    {s.label}
                  </button>
                ))}
              </div>
            </div>
         </div>

         {/* Rigging & Asset Panel */}
         <div className="w-80 bg-slate-900/50 backdrop-blur-xl rounded-[3rem] border border-white/5 p-10 flex flex-col gap-10 shadow-2xl">
            <h3 className="text-[11px] font-black text-slate-500 uppercase tracking-widest flex items-center"><Users className="w-5 h-5 mr-3 text-indigo-400" /> Synthesis Hub</h3>

            <div className="flex-1 space-y-6 overflow-y-auto custom-scrollbar">
               <div className="space-y-4">
                  <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Motion Rigging</p>
                  {[
                    { id: 1, label: 'Standard Skeleton', icon: Ghost },
                    { id: 2, label: 'Facial Mesh v2', icon: Eye },
                    { id: 3, label: 'Dynamic Posing', icon: Move3d },
                  ].map(m => (
                    <div key={m.id} className="p-5 bg-black/40 border border-white/5 rounded-3xl flex items-center justify-between group hover:border-indigo-500/40 transition-all cursor-pointer shadow-lg">
                        <div className="flex items-center space-x-4">
                          <m.icon className="w-5 h-5 text-indigo-400 group-hover:scale-110 transition-transform" />
                          <span className="text-[10px] font-black uppercase text-slate-400 group-hover:text-white transition-colors">{m.label}</span>
                        </div>
                        <Zap className="w-4 h-4 text-slate-800 group-hover:text-amber-500 transition-colors" />
                    </div>
                  ))}
               </div>

               <div className="pt-6 border-t border-white/5 space-y-4">
                  <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Asset Presets</p>
                  <div className="grid grid-cols-2 gap-3">
                     {['Cyber', 'Fantasy', 'Scifi', 'Gothic'].map(p => (
                       <button key={p} className="py-4 bg-slate-800/40 rounded-2xl text-[8px] font-black uppercase text-slate-500 border border-slate-700 hover:text-white hover:border-white/20 transition-all">{p}</button>
                     ))}
                  </div>
               </div>
            </div>

            <button className="w-full py-5 bg-slate-800 hover:bg-slate-750 border border-slate-700 rounded-[1.8rem] text-[10px] font-black uppercase tracking-widest transition-all flex items-center justify-center shadow-xl group">
               <BoxSelect className="w-5 h-5 mr-3 text-indigo-400 group-hover:scale-110 transition-transform" /> Export Mesh (OBJ)
            </button>
         </div>
      </div>
    </div>
  );
