                    placeholder="kader" 
                  />
                  <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-700 hover:text-white transition-colors">
                    {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                  </button>
                </div>
              </div>
            </div>

            <button disabled={isSubmitting} className="w-full py-6 bg-indigo-600 hover:bg-indigo-500 text-white rounded-[2rem] font-black uppercase text-[11px] tracking-[0.4em] shadow-xl shadow-indigo-600/20 transition-all flex items-center justify-center relative overflow-hidden group">
              <div className="absolute inset-0 bg-white/10 translate-y-full group-hover:translate-y-0 transition-transform duration-300" />
              {isSubmitting ? <RefreshCw className="w-6 h-6 animate-spin relative z-10" /> : 
               <span className="relative z-10 flex items-center">
                 {authView === 'login' ? 'Authorize Identity' : authView === 'signup' ? 'Deploy Node' : 'Recover Key'} 
                 <ShieldCheck className="w-5 h-5 ml-4" />
               </span>}
            </button>
          </form>

          <div className="mt-8 pt-8 border-t border-slate-800/50 text-center">
             <button onClick={() => setAuthView(authView === 'login' ? 'signup' : 'login')} className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-600 hover:text-indigo-400 transition-all">
               {authView === 'login' ? 'Initialize New Node Identity' : 'Return to Core Authorization'}
             </button>
          </div>
        </div>
      </div>

      <p className="fixed bottom-10 left-1/2 -translate-x-1/2 text-[9px] font-black text-slate-800 uppercase tracking-[0.5em] select-none">Lumina High-Security Desktop Infrastructure v4.5.1-STABLE</p>
    </div>
  );
};

