  BookOpen, FileSpreadsheet, Lock, Unlock, Zap, Layers, Server, Globe,
  Network, Code, Radio, Settings, PowerOff
} from 'lucide-react';
import { UserProfile, SiteConfig } from '../types';
import { api } from '../services/apiService';

type AdminTab = 'nodes' | 'matrix' | 'system' | 'config';

const AdminPanel: React.FC = () => {
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [loginStep, setLoginStep] = useState<'creds' | 'otp'>('creds');
  const [adminCreds, setAdminCreds] = useState({ email: 'admin@lumina.com', password: '' });
  const [otpValue, setOtpValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [activeTab, setActiveTab] = useState<AdminTab>('system');
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [siteConfig, setSiteConfig] = useState<SiteConfig>({
    maintenanceMode: false,
    activeModules: { video: true, photo: true, paint: true, ads: true, office: true, shop: true },
    globalAnnouncement: "System normal. All nodes operational."
  });
  const [systemStats, setSystemStats] = useState({ cpu: 42, memory: 68, storage: 84, traffic: 1204, threats: 0 });

  const loadData = async () => {
    setIsRefreshing(true);
    try {
      const fetchedUsers = await api.getUsers();
      setUsers(fetchedUsers);
    } catch (e) {
      console.error("Admin data fetch failed", e);
    } finally {
      setIsRefreshing(false);
    }
  };

  useEffect(() => {
    if (isUnlocked) loadData();
    const interval = setInterval(() => {
      setSystemStats(prev => ({
        ...prev,
        cpu: Math.floor(Math.random() * 20) + 30,
        memory: Math.floor(Math.random() * 10) + 60,
        traffic: prev.traffic + Math.floor(Math.random() * 10),
        threats: Math.random() > 0.98 ? prev.threats + 1 : prev.threats
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, [isUnlocked]);

  const handleInitialLogin = async () => {
    setIsProcessing(true);
    setError(null);
    try {
      await api.adminLogin(adminCreds);
      setLoginStep('otp');
    } catch (e: any) {
      setError(e.message || "Invalid identity credentials");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleOtpVerify = async () => {
    setIsProcessing(true);
    setError(null);
    try {
      const res = await api.verifyAdminOtp({ email: adminCreds.email, otp: otpValue });
      localStorage.setItem('lumina_token', res.token);
      setIsUnlocked(true);
    } catch (e: any) {
      setError(e.message || "OTP verification failed");
    } finally {
      setIsProcessing(false);
    }
