              <h2 className="text-4xl font-black text-white uppercase tracking-tighter">Root Authorization Required</h2>
              <p className="text-[10px] font-black text-rose-500/60 uppercase tracking-[0.5em] animate-pulse text-center">Classified Terminal Access Zone</p>
           </div>
           {error && (
