                 </div>

                 <div className="bg-black/80 border border-slate-900 rounded-[4rem] p-12 space-y-10">
                    <h4 className="text-xl font-black uppercase text-rose-500 flex items-center"><ShieldAlert className="w-6 h-6 mr-4" /> Hardened Mode</h4>
                    <div className="p-10 bg-rose-500/5 border border-rose-500/20 rounded-[3rem] space-y-6">
                       <p className="text-xs text-slate-500 font-bold leading-relaxed uppercase">Activating maintenance mode will suspend all non-root sessions and redirect users to a system standby page.</p>
                       <button 
                         onClick={() => setSiteConfig(prev => ({...prev, maintenanceMode: !prev.maintenanceMode}))}
                         className={`w-full py-6 rounded-3xl text-[11px] font-black uppercase tracking-[0.4em] transition-all flex items-center justify-center ${siteConfig.maintenanceMode ? 'bg-emerald-600 text-white' : 'bg-rose-600 text-white'}`}
                       >
                         {siteConfig.maintenanceMode ? <Power className="w-6 h-6 mr-3" /> : <PowerOff className="w-6 h-6 mr-3" />}
                         {siteConfig.maintenanceMode ? 'Restore Normal Ops' : 'Initiate Global Standby'}
                       </button>
                    </div>

                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-slate-700 uppercase tracking-widest ml-4">Global Announcement Feed</label>
                       <textarea 
                         value={siteConfig.globalAnnouncement}
                         onChange={e => setSiteConfig(prev => ({...prev, globalAnnouncement: e.target.value}))}
                         className="w-full bg-slate-950 border border-slate-900 rounded-[2rem] p-8 text-xs text-emerald-500 font-mono outline-none focus:border-emerald-500/50 resize-none h-40" 
                       />
                    </div>
                 </div>
              </div>
           </div>
        )}

        {activeTab === 'nodes' && (
          <>
            <div className="p-12 border-b border-slate-900 bg-black/40 backdrop-blur-xl flex flex-col md:flex-row items-center justify-between gap-10">
              <h3 className="text-2xl font-black uppercase tracking-tighter flex items-center text-white">
                  <Server className="w-7 h-7 mr-4 text-emerald-500" /> Active System Nodes
              </h3>
              <div className="flex items-center space-x-5">
                  <button onClick={loadData} className={`p-5 bg-slate-900 rounded-[1.5rem] text-slate-400 hover:text-white transition-all ${isRefreshing ? 'animate-spin' : ''}`}>
                    <RefreshCw className="w-5 h-5" />
                  </button>
                  <div className="relative w-80">
                    <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
                    <input placeholder="Search Clusters..." className="w-full bg-slate-950 border border-slate-900 rounded-[1.5rem] py-4 pl-16 pr-6 text-[10px] font-black uppercase text-white outline-none focus:border-emerald-500/50" />
                  </div>
              </div>
            </div>

            <div className="flex-1 overflow-auto p-12">
                <div className="animate-in fade-in slide-in-from-bottom-4 duration-700 overflow-hidden border border-slate-900 rounded-[3rem]">
                    <table className="w-full text-left">
                      <thead>
                          <tr className="bg-black text-[10px] uppercase font-black text-slate-700 tracking-[0.4em] border-b border-slate-900">
                            <th className="px-10 py-8">Node_Identity</th>
                            <th className="px-10 py-8">Access_Zone</th>
                            <th className="px-10 py-8">Authorization_Tier</th>
                            <th className="px-10 py-8 text-right">Ops</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-900/40">
                          {users.map(u => (
                            <tr key={u.email} className="group hover:bg-emerald-500/[0.02] transition-all">
                              <td className="px-10 py-8">
                                  <div className="flex items-center space-x-5">
                                    <div className="w-12 h-12 rounded-2xl bg-slate-900 border border-white/5 overflow-hidden group-hover:scale-105 transition-transform">
                                      <img src={u.avatar} className="w-full h-full object-cover" alt="" />
                                    </div>
                                    <div>
                                        <p className="text-sm font-black text-white uppercase tracking-tight">{u.name}</p>
                                        <p className="text-[10px] text-slate-600 font-mono">{u.email}</p>
                                    </div>
                                  </div>
                              </td>
                              <td className="px-10 py-8">
                                  <span className={`text-[8px] font-black uppercase px-4 py-1.5 rounded-lg border ${u.isBlocked ? 'bg-rose-500/10 text-rose-500 border-rose-500/20' : 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20 shadow-[0_0_10px_rgba(16,185,129,0.1)]'}`}>
                                    {u.isBlocked ? 'SUSPENDED' : 'ENABLED'}
                                  </span>
                              </td>
                              <td className="px-10 py-8 text-[11px] font-black text-indigo-500 uppercase tracking-[0.2em]">{u.plan}</td>
                              <td className="px-10 py-8 text-right">
                                  <div className="flex items-center justify-end space-x-3">
                                     <button className="p-3 bg-slate-900 text-slate-600 hover:text-white rounded-xl transition-all"><Eye className="w-4 h-4" /></button>
                                     <button className="p-3 bg-slate-900 text-slate-600 hover:text-rose-500 rounded-xl transition-all"><Trash2 className="w-4 h-4" /></button>
                                  </div>
                              </td>
                            </tr>
                          ))}
                      </tbody>
                    </table>
                </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;
